export const FEATURE_DETAILS: Record<number, FeatureDetail> = {
  101: {"description": "A core nCino feature where a user (typically a relationship manager) either creates a new customer relationship or updates an existing one (e.g. a change of address or additional detail). The user opens a drop-down to create a relationship, adds basic customer details (nothing is mandatory in nCino to create the record), and can update it later. For larger banks that run a separate customer-master onboarding system, creation can be triggered from nCino while updates may have to be made in the customer master instead. Links to the heat map box 'Create or Update Relationship'.", "roles": ["Relationship Manager (primary)"], "process_steps": [{"step": "RM identifies there is no existing relationship (new customer) or an existing one needs updating", "source": "evidenced"}, {"step": "Open the create-relationship drop-down and add a new relationship", "source": "evidenced"}, {"step": "Enter basic customer details (no mandatory fields enforced by nCino)", "source": "evidenced"}, {"step": "Once created, update the relationship record as needed", "source": "evidenced"}, {"step": "For banks with a customer master, creation may trigger downstream; updates may route back to the customer master rather than nCino", "source": "evidenced", "note": "Transcript flags this as a potential integration to work through"}, {"step": "Search for an existing relationship before creating, to prevent duplicate records", "source": "inferred", "note": "Standard nCino gold-standard 'search-first' practice; SME to confirm for Raiffeisen"}, {"step": "Select the relationship record type (Individual / Business)", "source": "inferred", "note": "SME to confirm record types in use"}], "common_integrations": ["Customer-master / onboarding system"], "community_articles": [{"title": "How to Configure Consumer In-Branch Relationship Onboarding: Relationship Types", "url": "https://ncino.my.site.com/s/article/HowtoConfigureConsumerInBranchRelationshipOnboardingRelationshipTypes"}, {"title": "How to Use the Customer Engagement Solution: Guide for Administrators", "url": "https://ncino.my.site.com/s/article/HowtoUsetheCustomerEngagementSolutionGuideforAdministrators"}]},
  102: {"description": "Part of relationship creation: the user provides a tax ID or external party ID and nCino looks the entity up against external registers to retrieve company information (directors, addresses, full details), relieving manual data entry. Other third-party providers can return richer data such as financials/spreads when given the right identifier. Not all businesses support this and not all banks use nCino for it. Links to the heat map box 'Business Lookup'.", "roles": ["Relationship Manager / whoever performs onboarding (primary)"], "process_steps": [{"step": "Provide a tax ID or external party ID during relationship creation", "source": "evidenced"}, {"step": "nCino looks up external registers (e.g. Companies House) to retrieve directors, addresses and full company details", "source": "evidenced"}, {"step": "Optionally retrieve additional data (financials, spreads) from other third-party providers using the right ID", "source": "evidenced"}, {"step": "Use returned data to populate the customer/relationship record instead of manual entry", "source": "evidenced"}, {"step": "Select provider, review the results table, choose the correct entity and save — creating a Company Information record and updating the Relationship", "source": "inferred", "note": "Standard BLUP behaviour per Community; SME to confirm provider(s) and field mapping for Raiffeisen"}], "common_integrations": ["Companies House", "Other third-party data/financial providers"], "community_articles": []},
  103: {"description": "Building out connections within nCino to link relationships into a structure — a household or credit group. Connection records tie two relationships together and can be bi-directional (e.g. owner / subsidiary) or direct (e.g. co-owner / co-owner) via different connection types. The structure is viewed through the native Salesforce parent hierarchy visual rather than the out-of-the-box list view, and exposure can be built from it (also via entity involvement, covered later). Links to the heat map box 'Hierarchy Visualization'. NB: this is the relationship/credit-group hierarchy, distinct from the loan facility hierarchy visualizer.", "roles": ["Relationship Manager (primary)", "Credit Analyst (may get involved)", "KYC person (may get involved in connections/structure)"], "process_steps": [{"step": "Create connection records to link two relationships", "source": "evidenced"}, {"step": "Set the connection type/direction (bi-directional owner/subsidiary, or direct co-owner/co-owner)", "source": "evidenced"}, {"step": "Build out the structure into a household or credit group", "source": "evidenced"}, {"step": "Visualise the structure via the native Salesforce parent hierarchy visual (vs list view)", "source": "evidenced"}, {"step": "Build exposure from the structure (also achievable via entity involvement)", "source": "evidenced"}, {"step": "Configure connection roles with reciprocal roles so the connection tree renders", "source": "inferred", "note": "Standard nCino config; SME to confirm"}, {"step": "Create a Household record type and configure relationship statistics for credit-group exposure", "source": "inferred", "note": "Per Households gold standard; SME to confirm Raiffeisen exposure config"}], "common_integrations": ["Customer master"], "community_articles": [{"title": "Gold Standard: Households", "url": "https://ncino.my.site.com/s/article/kAHHu000000XZU4OAO"}, {"title": "How to Configure Household (Deposits)", "url": "https://ncino.my.site.com/s/article/kAHHu000000XaDsOAK"}]},
  104: {"description": "With the customer set up, the customer now has a need (they provide an input, go direct to the banker, or the banker reaches out via marketing tools to identify the need). In this need-identification step the user captures the preliminary information in the Deal Proposal: the basics of the need — who the customer is, who is looking for the need, and what they want — before moving to the next step. Deal Proposal in nCino is usually done by the relationship manager. Links to the heat map box 'Capture Preliminary Info' (Deal Proposal).", "roles": ["Relationship Manager (primary)"], "process_steps": [{"step": "Customer need is identified (customer input, direct approach to the banker, or banker outreach via marketing tools)", "source": "evidenced"}, {"step": "With the customer/relationship already set up, open the Deal Proposal to capture the need", "source": "evidenced"}, {"step": "Capture the basics of the need: who the customer is, who is looking for the need, and what they want", "source": "evidenced"}, {"step": "Move the deal proposal to the next step", "source": "evidenced"}, {"step": "Create the Deal Proposal record linked to the relationship/account", "source": "inferred", "note": "Standard Deal Proposal lifecycle; SME to confirm for Raiffeisen"}, {"step": "Capture requested amount / purpose at a high level", "source": "inferred", "note": "SME to confirm preliminary fields captured"}], "common_integrations": ["Marketing tools"], "community_articles": [{"title": "How to Use Deal Proposal", "url": "https://ncino.my.site.com/s/article/HowtoUseDealProposal"}, {"title": "How to Configure Deal Proposal - Required Configuration", "url": "https://ncino.my.site.com/s/article/How-to-Configure-Deal-Proposal"}, {"title": "How to Configure Deal Proposal - Additional Configuration", "url": "https://ncino.my.site.com/s/article/HowtoConfigureDealProposalAdditionalConfiguration"}]},
  105: {"description": "Based on the need identified, the relationship manager selects the right product(s) to meet that need, all within the deal proposal — e.g. you would not offer a construction loan to someone looking for a fleet of vehicles, so you make sure the product fits the need (banks sometimes have regulations around this). At this point the user also captures the amount, the branch or area, and some initial details such as how long they might want the loan for (the term) — just the basics. Links to the heat map box 'Select Product(s)' (Product Selection).", "roles": ["Relationship Manager (primary)"], "process_steps": [{"step": "Review the identified need to determine suitable product(s)", "source": "evidenced"}, {"step": "Select the right product(s) to meet the need, within the deal proposal (ensuring product fits the need, e.g. not a construction loan for a vehicle fleet)", "source": "evidenced"}, {"step": "Apply any bank regulations/rules constraining product choice", "source": "evidenced", "note": "Transcript notes 'sometimes banks have regulations around this'"}, {"step": "Capture the amount", "source": "evidenced"}, {"step": "Capture the branch or area", "source": "evidenced"}, {"step": "Capture some initial details such as the term (how long they might want the loan for)", "source": "evidenced"}, {"step": "Add selected products to the Product Package on the deal", "source": "inferred", "note": "Standard nCino product selection populates the Product Package; SME to confirm"}], "common_integrations": [], "community_articles": [{"title": "How to Configure Product Package", "url": "https://ncino.my.site.com/s/article/HowtoConfigureProductPackage"}, {"title": "How to Use Product Package", "url": "https://ncino.my.site.com/s/article/HowtoUseProductPackage"}, {"title": "How to Configure Change Product", "url": "https://ncino.my.site.com/s/article/HowtoConfigureChangeProduct"}, {"title": "How to Configure Deal Proposal - Required Configuration", "url": "https://ncino.my.site.com/s/article/How-to-Configure-Deal-Proposal"}]},
  106: {"description": "The end of the preliminary-information / product-selection / advancing-the-deal flow, which usually results in the generation of a term sheet. Advancing the deal means: the customer's information for their need has been captured, it is played back to the customer to confirm it is correct, and once confirmed the relationship manager decides this is something to proceed with and moves to the next stage. Having created the deal proposal and confirmed it with the customer by selecting the product, the relationship manager passes it on to qualification — finishing prospecting. Links to the heat map box 'Advance Deal' (Product Package / Deal).", "roles": ["Relationship Manager (primary)"], "process_steps": [{"step": "Play back the captured customer/need information to the customer to confirm it is correct", "source": "evidenced"}, {"step": "Once confirmed correct, decide to proceed with the deal", "source": "evidenced"}, {"step": "Advance/move the deal to the next stage", "source": "evidenced"}, {"step": "Relationship manager passes the deal on to qualification (prospecting finished)", "source": "evidenced"}, {"step": "Generate a term sheet at the end of the preliminary-info / product-selection / advance step", "source": "evidenced", "note": "Transcript: 'usually what this ends up in is the generation of a term sheet'"}, {"step": "Advance the Product Package / deal status to move the workflow forward", "source": "inferred", "note": "Standard nCino deal/product-package progression; SME to confirm status model"}], "common_integrations": [], "community_articles": [{"title": "Gold Standard: Product Package", "url": "https://ncino.my.site.com/s/article/kAHHu000000XZUDOA4"}, {"title": "How to Configure Product Package", "url": "https://ncino.my.site.com/s/article/HowtoConfigureProductPackage"}, {"title": "How to Use Deal Proposal", "url": "https://ncino.my.site.com/s/article/HowtoUseDealProposal"}, {"title": "How to Configure Deal Proposal - Required Configuration", "url": "https://ncino.my.site.com/s/article/How-to-Configure-Deal-Proposal"}]},
  201: {"description": "A full onboarding of the customer during qualification - KYC for individuals or AML for entities. This is not native to nCino commercial lending; it is often performed in a separate system or via an integration, especially for brand-new customers or where additional checks are required, and may involve waiting for status updates before the deal can proceed. In nCino this is the domain of Customer Lifecycle Management (CLM) / Customer Onboarding, which the transcript notes will likely be covered by a separate heat map. Links to the heat map box 'Onboarding new customer'.", "roles": [], "process_steps": [{"step": "Determine whether the customer needs full onboarding (e.g. brand-new customer or additional checks required)", "source": "evidenced"}, {"step": "Perform KYC for individuals or AML for entities", "source": "evidenced"}, {"step": "Where onboarding is not done in nCino, route the customer through an integration to a separate system", "source": "evidenced"}, {"step": "Wait for onboarding status updates before proceeding with the deal", "source": "evidenced"}, {"step": "Create an onboarding case and run screening (AML/CIFAS/KYB/Business Credit/Identity Verification), then remediate any flags", "source": "inferred", "note": "Standard nCino CLM behaviour per Community; SME to confirm Raiffeisen onboarding approach (CLM vs external system)"}, {"step": "Capture related parties (corporate structure and related officers) as part of the case", "source": "inferred", "note": "SME to confirm"}], "common_integrations": ["External onboarding / KYC-AML system"], "community_articles": [{"title": "How to Use Client Lifecycle Management", "url": "https://ncino.my.site.com/s/article/HowtoUseClientLifecycleManagement"}, {"title": "How to Configure Client Lifecycle Management", "url": "https://ncino.my.site.com/s/article/HowtoConfigureClientLifecycleManagement"}]},
  202: {"description": "An early qualification activity - not always mandatory at this stage - which can be an internal or an external credit check. An internal check applies to an existing customer, confirming they have no flags such as bankruptcies, insolvencies or missed payments. An external check involves providing a third-party ID so a bureau runs its own credit checks to confirm the customer is not flagging with other banks. This is typically where work starts from a credit analyst perspective; depending on complexity the credit check may be a credit analyst rather than a relationship manager activity. Links to the heat map box 'Run Credit Check'.", "roles": ["Credit Analyst (primary, depending on complexity)", "Relationship Manager (may perform simpler checks)"], "process_steps": [{"step": "Decide whether a credit check is needed (not always mandatory at this stage)", "source": "evidenced"}, {"step": "Run an internal credit check for existing customers - check for flags such as bankruptcies, insolvencies, missed payments", "source": "evidenced"}, {"step": "For an external check, provide a third-party ID so a bureau runs its own credit checks against other banks", "source": "evidenced"}, {"step": "Review the results to confirm nothing is flagging before proceeding", "source": "evidenced"}, {"step": "Configure and call the third-party credit bureau via an integration / service management and store the returned result against the record", "source": "inferred", "note": "nCino has no dedicated native 'credit check' feature; this is normally a third-party data integration. SME to confirm Raiffeisen's bureau provider and how results are surfaced"}], "common_integrations": ["External credit bureau / third-party credit-check provider"], "community_articles": [{"title": "How to Use Credit Reporting", "url": "https://ncino.my.site.com/s/article/HowtoUseCreditReporting"}, {"title": "How to Configure Credit Underwriting: Credit Reporting Integrations", "url": "https://ncino.my.site.com/s/article/HowtoConfigureCreditUnderwritingCreditReportingIntegrations"}]},
  203: {"description": "Building out additional loan information beyond the basics captured during prospecting. The term, product and possibly the loan purpose are already captured; here the user enriches the detail - for example whether the customer wants a multi-tier loan or a single loan as part of the package, plus any other aspects. Typically done by the relationship manager or the credit analyst depending on the size of the institution. Links to the heat map box 'Build Loan Information'.", "roles": ["Relationship Manager (depending on institution size)", "Credit Analyst (depending on institution size)"], "process_steps": [{"step": "Start from the already-captured term, product and (possibly) loan purpose", "source": "evidenced"}, {"step": "Capture additional loan detail - e.g. multi-tier loan vs single loan within the package", "source": "evidenced"}, {"step": "Add any other relevant loan aspects", "source": "evidenced"}, {"step": "Populate standard Loan object fields (amounts, dates, loan type/purpose, structure attributes) on the loan record", "source": "inferred", "note": "Standard nCino Loan object data capture; SME to confirm Raiffeisen field set"}], "common_integrations": [], "community_articles": [{"title": "Gold Standard: Multi-Tiered Loans", "url": "https://ncino.my.site.com/s/article/kAHHu000000XZTlOAO"}, {"title": "Gold Standard: Product Package", "url": "https://ncino.my.site.com/s/article/kAHHu000000XZUDOA4"}]},
  204: {"description": "A feature for building out the loan team - the individuals within nCino who will actually work on the loan from the bank side: credit analyst, relationship manager, credit officer, operations, etc. It can be a team or an individual assigned. Assigning the team gives people early indication that they will receive activities for the deal, so everyone knows who is doing what. Links to the heat map box 'Loan Team'.", "roles": ["Credit Analyst (as a team member)", "Relationship Manager (as a team member)", "Credit Officer (as a team member)", "Operations (as a team member)"], "process_steps": [{"step": "Identify the bank-side individuals who will work on the loan", "source": "evidenced"}, {"step": "Assign roles - credit analyst, relationship manager, credit officer, operations", "source": "evidenced"}, {"step": "Assign either a team or an individual to each role", "source": "evidenced"}, {"step": "Give early indication to assignees that they will receive activities for the deal", "source": "evidenced"}, {"step": "Configure loan-team roles and any automated/role-based assignment rules", "source": "inferred", "note": "Standard nCino Team Management config; SME to confirm Raiffeisen role set and assignment automation"}], "common_integrations": [], "community_articles": [{"title": "How to Use Team Management", "url": "https://ncino.my.site.com/s/article/HowtoUseTeamManagement"}, {"title": "How to Configure Team Management", "url": "https://ncino.my.site.com/s/article/HowtoConfigureTeamManagement202504"}]},
  205: {"description": "Building out the borrowing structure for the bank, commonly known as entity involvement (the two terms are interchangeable). From this you identify the borrowers, co-borrowers and guarantors involved in the facility. Other borrowing structure / entity involvement types may exist, but borrower, co-borrower and guarantor are typically the main ones. Links to the heat map box 'Borrowing Structure'.", "roles": [], "process_steps": [{"step": "After identifying the loan team, build out the borrowing structure (entity involvement) for the bank", "source": "evidenced"}, {"step": "Identify the borrowers involved in the facility", "source": "evidenced"}, {"step": "Identify co-borrowers involved in the facility", "source": "evidenced"}, {"step": "Identify guarantors involved in the facility", "source": "evidenced"}, {"step": "Add other entity-involvement types as needed", "source": "evidenced", "note": "Transcript notes other types may exist but borrower/co-borrower/guarantor are the main ones"}, {"step": "Create entity involvement records linking the relationships to the deal/loan with the correct involvement type and ownership/percentage detail", "source": "inferred", "note": "Standard nCino Entity Involvement behaviour; SME to confirm Raiffeisen involvement types and ownership capture"}], "common_integrations": [], "community_articles": [{"title": "How to Configure Entity Involvement", "url": "https://ncino.my.site.com/s/article/HowtoConfigureEntityInvolvement"}, {"title": "How to Use Entity Involvement", "url": "https://ncino.my.site.com/s/article/HowtoUseEntityInvolvement"}, {"title": "How to Configure Classic Entity Involvement - Spring 2020", "url": "https://ncino.my.site.com/s/article/HowtoConfigureClassicEntityInvolvementSpring2020"}, {"title": "How to Use Classic Entity Involvement - Fall 2019", "url": "https://ncino.my.site.com/s/article/HowtoUseClassicEntityInvolvementFall2019"}]},
  206: {"description": "Capturing the basics of loan structuring - rates and payments. Building on the initially-captured term, the user now captures interest rates, fixed/variable, and clarifies the repayment schedule. Information captured includes interest rate type, the tracker, baselines, terms and repayment schedule, all within loan structuring / rates and payments. Typically done by the credit analyst. Multiple versions can be captured, allowing iteration - producing two or three different versions and changing as the deal develops. Links to the heat map box 'Loan Structuring (Rates & Payments)'.", "roles": ["Credit Analyst (typical)"], "process_steps": [{"step": "Start from the initially-captured term information", "source": "evidenced"}, {"step": "Capture interest rates and whether fixed or variable", "source": "evidenced"}, {"step": "Capture interest rate type, tracker and baselines", "source": "evidenced"}, {"step": "Clarify and capture the repayment schedule", "source": "evidenced"}, {"step": "Capture multiple versions to iterate (produce two or three different versions and change as you go)", "source": "evidenced"}, {"step": "Configure rate indices/baselines and payment structure templates that drive the calculations", "source": "inferred", "note": "Standard nCino Rate and Payment Structures config; SME to confirm Raiffeisen rate types and indices"}], "common_integrations": [], "community_articles": [{"title": "How to Use Loan Structuring", "url": "https://ncino.my.site.com/s/article/HowtoUseLoanStructuring"}, {"title": "How to Configure Loan Structuring", "url": "https://ncino.my.site.com/s/article/HowtoConfigureLoanStructuring"}, {"title": "How to Use Rate and Payment Structure Enhancements in the Loan Structuring Experience - 2025_05", "url": "https://ncino.my.site.com/s/article/How-to-Use-Rate-and-Payment-Enhancements-in-the-Loan-Structuring-Experience202505"}, {"title": "How to Configure Rate and Payment Structure Enhancements in the Loan Structuring Experience - 2025_05", "url": "https://ncino.my.site.com/s/article/How-to-Configure-Rate-and-Payment-Enhancements-in-the-Loan-Structuring-Experience202505"}, {"title": "How to Use Rate and Payment Structures - Fall 2022", "url": "https://ncino.my.site.com/s/article/HowtoUseRateandPaymentStructuresFall2022"}]},
  207: {"description": "An amortisation schedule that can only be started once loan structuring (206) is complete and all loan details are captured. It is a document or overview across each of the terms - monthly, annually, bi-monthly - showing the repayment amount and how much is fixed, and how much is interest versus principal. It is a visual. Sherman is nCino's back-end calculation engine that produces it. Some banks choose to do this in their own external system. Links to the heat map box 'Amortisation Schedule (Sherman)'.", "roles": [], "process_steps": [{"step": "Confirm loan structuring is complete (cannot start until all loan-structuring details captured)", "source": "evidenced"}, {"step": "Generate the amortisation schedule across the terms (monthly, annually, bi-monthly)", "source": "evidenced"}, {"step": "Review repayment amount and the split of interest vs principal (and how much is fixed) per period", "source": "evidenced"}, {"step": "Use the schedule as a visual overview", "source": "evidenced"}, {"step": "Sherman (back-end calculation engine) computes the schedule values", "source": "evidenced", "note": "Transcript names Sherman as nCino's calculation engine; some banks use their own external system instead"}, {"step": "Configure the schedule template / Sherman engine parameters for the institution's payment frequencies", "source": "inferred", "note": "Standard nCino Schedules config; SME to confirm whether Raiffeisen uses Sherman or an external amortisation system"}], "common_integrations": ["External amortisation / calculation system"], "community_articles": [{"title": "How to Use Loan Structuring", "url": "https://ncino.my.site.com/s/article/HowtoUseLoanStructuring"}, {"title": "How to Configure Loan Structuring", "url": "https://ncino.my.site.com/s/article/HowtoConfigureLoanStructuring"}, {"title": "How to Use Rate and Payment Structures", "url": "https://ncino.my.site.com/s/article/HowtoUseRateandPaymentStructures"}]},
  208: {"description": "Adding associated fees to the actual facility or facilities. Fee management is not dependent on the amortisation schedule (207) or loan structuring (206). Fees are added at a loan level, not at a product package or deal level. Fees can be associated to products inherently, so selecting a product can bring standard fees that always apply. A fee can be a monetary amount or a percentage of another amount, typically based on the loan amount. Typically done by the credit analyst or relationship manager, though operations may finalise it later - so it can be updated and is not critical to credit approval. Links to the heat map box 'Fee Management'.", "roles": ["Credit Analyst (typical)", "Relationship Manager (typical)", "Operations (may finalise later)"], "process_steps": [{"step": "Add associated fees to the facility/facilities at the loan level", "source": "evidenced"}, {"step": "Use product-inherent fees - selecting a product may bring standard fees that always apply", "source": "evidenced"}, {"step": "Set each fee as a monetary amount or a percentage of another amount (typically the loan amount)", "source": "evidenced"}, {"step": "Update/finalise fees later (operations may do this; not critical to credit approval)", "source": "evidenced"}, {"step": "Configure fee types and product-fee associations in setup", "source": "inferred", "note": "Standard nCino Fee Management config; SME to confirm Raiffeisen fee types and product associations"}], "common_integrations": [], "community_articles": [{"title": "How to Use Fee Management for Commercial, Retail, and Small Business Loans", "url": "https://ncino.my.site.com/s/article/HowtoUseFeeManagementforCommercialRetailandSmallBusinessLoans"}, {"title": "How to Configure Fee Management", "url": "https://ncino.my.site.com/s/article/HowtoConfigureFeeManagement"}]},
  209: {"description": "Still in qualification - adding collateral or collateral groups to secure the loan. The relationship manager usually does the first version (how the loan is secured) but it may go to a specialist or credit analyst for full details. When adding collateral you can either take existing collateral from the customer or create new collateral; for new collateral you select the type and subtype then capture the basics for the amounts the collateral is worth, with valuations potentially done later. Collateral groups are used for large pieces of collateral (e.g. fleets of vehicles) - rather than creating individual collateral records and valuations, you classify it as a group. Collateral groups are not commonly used but are available in nCino. Links to the heat map box 'Add collateral & collateral groups (Collateral Mgmt)'.", "roles": ["Relationship Manager (usually does the first version)", "Specialist (may take over for full details)", "Credit Analyst (may take over for full details)"], "process_steps": [{"step": "Relationship manager creates the first version - how the loan is being secured", "source": "evidenced"}, {"step": "Hand off to a specialist or credit analyst for full collateral detail if needed", "source": "evidenced"}, {"step": "Either take existing collateral from the customer, or create new collateral", "source": "evidenced"}, {"step": "For new collateral, select the type and subtype", "source": "evidenced"}, {"step": "Capture the basics for the amounts the collateral is worth", "source": "evidenced"}, {"step": "Perform valuations against the collateral later", "source": "evidenced", "note": "Transcript notes valuations 'may' be done later"}, {"step": "For large collateral (e.g. fleets of vehicles), classify as a collateral group rather than individual records", "source": "evidenced", "note": "Transcript: collateral groups not commonly used but available"}, {"step": "Link collateral to the loan/facility and set lien/coverage detail", "source": "inferred", "note": "Standard nCino Collateral Management behaviour; SME to confirm Raiffeisen collateral types/subtypes and valuation process"}], "common_integrations": [], "community_articles": [{"title": "How to Use Collateral Management", "url": "https://ncino.my.site.com/s/article/HowtoUseCollateralManagement"}, {"title": "How to Use Enhanced Collateral Management - Spring 2022", "url": "https://ncino.my.site.com/s/article/HowtoUseEnhancedCollateralManagementSpring2022"}, {"title": "How to Configure Collateral Management - PART ONE - 2025_09", "url": "https://ncino.my.site.com/s/article/HowtoConfigureCollateralManagementPARTONE202509"}, {"title": "How to Configure Collateral Groups", "url": "https://ncino.my.site.com/s/article/HowtoConfigureCollateralGroups"}]},
  210: {"description": "Where there are multiple loans within a single product package, nCino provides bulk update features. The transcript stresses this is not really a process step but rather functionality - rather than amending a field across every loan individually (e.g. ten loans in a product package), you bulk update certain aspects at once. It surfaces as a pop-out sidebar that makes navigation easier. It can happen at any time, can be done by anyone, and is not really placed in qualification specifically. Links to the heat map box 'Bulk update and manage loans (Deal management)'.", "roles": [], "process_steps": [{"step": "Open the bulk update / deal management pop-out sidebar", "source": "evidenced"}, {"step": "Select the loans within the product package to update", "source": "evidenced", "note": "Implied by transcript example of 10 loans in a product package"}, {"step": "Bulk update certain aspects/fields across the selected loans at once (instead of editing each loan individually)", "source": "evidenced"}, {"step": "Use the sidebar to navigate and manage the loans more easily", "source": "evidenced"}], "common_integrations": [], "community_articles": [{"title": "How to Use Deal Management", "url": "https://ncino.my.site.com/s/article/HowtoUseDealManagement"}, {"title": "How to Configure Deal Management", "url": "https://ncino.my.site.com/s/article/HowtoConfigureDealManagement"}]},
  211: {"description": "Usually done by a credit analyst - adding covenants to the deal or the loan. Covenants are clauses provided by the bank to the customer (we will give you this on the condition of X, Y and Z), which the customer usually has to prove once the loan is funded on a frequent basis (annually, semi-annually, monthly). In nCino covenants behave essentially like signature collateral: there is a list of covenants with types and subtypes for the credit analyst to select, captured at the start. Covenants can be applied at a deal or loan level, and can be made to apply to relationships so that any further deals the customer has will have them applied automatically - preventing duplication and making covenants easier to manage. Links to the heat map box 'Add covenants to deal or loans (Covenant Servicing)'.", "roles": ["Credit Analyst (usual)"], "process_steps": [{"step": "Select covenants from a list of types and subtypes", "source": "evidenced"}, {"step": "Add covenants at a deal level or a loan level", "source": "evidenced"}, {"step": "Capture the covenants at the start of the deal", "source": "evidenced"}, {"step": "Optionally apply covenants to relationships so future deals inherit them automatically", "source": "evidenced", "note": "Transcript: prevents duplication, makes covenants easier to manage"}, {"step": "Set the proof/testing frequency (annually, semi-annually, monthly) for post-funding compliance", "source": "evidenced", "note": "Transcript states customer must prove covenants on a frequent basis once funded; testing/monitoring itself is downstream (see 306/802/803)"}, {"step": "Configure covenant types/subtypes and templates in setup", "source": "inferred", "note": "Standard nCino Covenant Management & Servicing config; SME to confirm Raiffeisen covenant catalogue"}], "common_integrations": [], "community_articles": [{"title": "How to Use Covenant Management and Servicing", "url": "https://ncino.my.site.com/s/article/HowtoUseCovenantManagementandServicing"}, {"title": "How to Configure Covenant Management & Servicing: Required Configuration", "url": "https://ncino.my.site.com/s/article/HowtoConfigureCovenantManagementandServicingRequiredConfiguration"}, {"title": "How to Configure Covenant Management & Servicing: Additional Configuration", "url": "https://ncino.my.site.com/s/article/HowtoConfigureCovenantManagementandServicingAdditionalConfiguration"}, {"title": "How to Use Covenant Servicing Sync to Placeholders", "url": "https://ncino.my.site.com/s/article/HowtoUseCovenantServicingSynctoPlaceholders"}, {"title": "How to Configure Automated Covenant Testing", "url": "https://ncino.my.site.com/s/article/HowtoConfigureAutomatedCovenantTesting"}, {"title": "How to Use Automated Covenant Testing", "url": "https://ncino.my.site.com/s/article/HowtoUseAutomatedCovenantTesting"}]},
  212: {"description": "Collecting and storing documents against a deal, a product package, a loan or a customer using the Document Manager - a repository with placeholders and a folder structure for storing documents relevant to the loan or deal in nCino. It needs to be configured: you set up the document types common to the deal, and documents can be tied to specific products so they automatically appear. Done by a relationship manager or credit analyst (sometimes a junior RM or admin helps), at any time. Good for metadata. Four-eyes checks on documents are sometimes applied if wanted. Typically used as the central store for all the deal's information. Links to the heat map box 'Collect & Store Documents (Document Manager)'.", "roles": ["Relationship Manager (primary)", "Credit Analyst (primary)", "Junior Relationship Manager (may help)", "Admin (may help)"], "process_steps": [{"step": "Collect and store documents against a deal, product package, loan or customer in the Document Manager", "source": "evidenced"}, {"step": "Use the repository's placeholders and folder structure to organise documents", "source": "evidenced"}, {"step": "Configure the document types common to the deal", "source": "evidenced", "note": "Transcript: 'This needs to be configured'"}, {"step": "Tie documents to specific products so they automatically appear", "source": "evidenced"}, {"step": "Capture metadata against documents", "source": "evidenced"}, {"step": "Apply four-eyes checks on documents where required", "source": "evidenced", "note": "Transcript: 'Sometimes there are 4-eyes checks on documents, applicable if you want it'"}, {"step": "Set up placeholder/folder structure and document-type-to-product mappings in configuration", "source": "inferred", "note": "Standard nCino Document Manager config; SME to confirm Raiffeisen document types and 4-eyes rules"}], "common_integrations": [], "community_articles": [{"title": "How to Use Document Manager", "url": "https://ncino.my.site.com/s/article/HowtoUseDocumentManager"}, {"title": "Gold Standard: Document Manager", "url": "https://ncino.my.site.com/s/article/kAHHu000000XZTEOA4"}, {"title": "How to Configure Document Manager - 2025_08", "url": "https://ncino.my.site.com/s/article/HowtoConfigureDocumentManager202508"}, {"title": "How to Configure Document Manager Placeholders", "url": "https://ncino.my.site.com/s/article/HowtoConfigureDocumentManagerPlaceholders"}, {"title": "How to Configure Document Manager Permissions", "url": "https://ncino.my.site.com/s/article/HowtoConfigureDocumentManagerPermissions"}]},
  213: {"description": "Beyond storing and collecting documents in the Document Manager, nCino can also generate documents through DocGen. This is the ability to use a standardised template across the bank containing variables (customer name, product name, amount, some small conditions). Documents can be generated by anyone (usually not restricted) from a standardised set of templates, and can be done at any time, not just in qualification. Typically used here to produce the term sheet, the offer letter or an indicative offer. Links to the heat map box 'Generate Documents (DocGen / FormsGen)'.", "roles": [], "process_steps": [{"step": "Select a standardised template from the bank's template set", "source": "evidenced"}, {"step": "Generate the document, populating template variables (customer name, product name, amount, small conditions)", "source": "evidenced"}, {"step": "Produce qualification-stage documents such as the term sheet, offer letter or indicative offer", "source": "evidenced"}, {"step": "Configure templates, variables/merge fields and any generation conditions in setup", "source": "inferred", "note": "Standard nCino Document Generation / Form Generation config; SME to confirm Raiffeisen template set"}], "common_integrations": [], "community_articles": [{"title": "Gold Standard: Form Generation", "url": "https://ncino.my.site.com/s/article/kAHHu000000XZSsOAO"}, {"title": "How to Use Form Generation", "url": "https://ncino.my.site.com/s/article/HowtoUseFormGeneration"}, {"title": "How to Configure Form Generation - Required Configuration", "url": "https://ncino.my.site.com/s/article/HowtoConfigureFormGeneration"}, {"title": "How to Configure Form Generation - Additional Configuration", "url": "https://ncino.my.site.com/s/article/HowtoConfigureFormGenerationAdditionalConfiguration"}, {"title": "How to Configure HTML Form Generation", "url": "https://ncino.my.site.com/s/article/HowtoConfigureHTMLFormGeneration"}, {"title": "How to Configure Automated Form Generation", "url": "https://ncino.my.site.com/s/article/HowtoConfigureAutomatedFormGeneration"}, {"title": "How to Configure nCino's Document Generation", "url": "https://ncino.my.site.com/s/article/HowtoConfigurenCinosDocumentGeneration"}]},
  301: {"description": "The opening underwriting activity, always performed by a credit analyst (potentially automated for SME loans, specialist-led for large corporates). The customer is asked to provide their last few years of finances (e.g. three years, or however long is needed), which must be verified and can sometimes be sourced from third parties. Credit underwriters/analysts then 'spread' that information — laying historic financials across periods alongside a forecast (e.g. next three years) to understand the customer's capacity to make repayments and confirm that what they are asking for is financially suitable and won't result in delinquencies. Links to the heat map box 'Gather & Analyse Financials' (Spreading).", "roles": ["Credit Analyst (primary)", "Credit Underwriter", "Specialist (for large corporate loans)"], "process_steps": [{"step": "Request the customer's financials (e.g. last three years, or as long as needed)", "source": "evidenced"}, {"step": "Verify the financials are accurate; sometimes obtained from third parties", "source": "evidenced"}, {"step": "Spread the historic financials across periods", "source": "evidenced"}, {"step": "Produce a forecast (e.g. next three years) alongside the historics", "source": "evidenced"}, {"step": "Analyse capacity to make repayments and confirm the request is financially suitable / won't cause delinquencies", "source": "evidenced"}, {"step": "Configure Spread Statement Templates, groups, rows and link types; add financial periods (standard, TTM, projections, average) in the Spreads UI", "source": "inferred", "note": "Standard Spreads behaviour per Community; SME to confirm Raiffeisen statement templates and period setup"}], "common_integrations": ["Third-party providers"], "community_articles": [{"title": "How to Configure Spreads - PART ONE", "url": "https://ncino.my.site.com/s/article/HowtoConfigureSpreadsPARTONE"}, {"title": "How to Use Spreads - PART ONE", "url": "https://ncino.my.site.com/s/article/HowtoUseSpreadsPARTONE202505"}, {"title": "How to Configure Spreads - PART TWO", "url": "https://ncino.my.site.com/s/article/HowtoConfigureSpreadsPARTTWO202509"}, {"title": "How to Use Spreads - PART TWO", "url": "https://ncino.my.site.com/s/article/HowtoUseSpreadsPARTTWO202502"}]},
  302: {"description": "A deeper analysis of the collateral that was loosely captured earlier in qualification (e.g. the RM may have just said 'machinery worth X'). The analyst now obtains and clarifies real detail — for machinery, the type, year, engine and model — and performs analysis on that collateral. For specific collateral types such as a large property owner, more detail is needed in the form of rent roll and tenancy management; for construction of apartments or large blocks, analysis of the forecast (rent rolls, tenancy management) establishes occupancy rate and predicted amounts to ensure the collateral remains sufficient in a downturn. Performed by a credit analyst, or in larger organisations a collateral specialist / tenancy-management / construction specialist. The transcript notes this is 'not really sequential'. Links to the heat map box 'Analyse Collateral' (Rent Roll and Tenancy Management).", "roles": ["Credit Analyst (primary)", "Collateral Specialist (larger orgs)", "Tenancy Management Specialist (larger orgs)", "Construction Specialist (larger orgs)"], "process_steps": [{"step": "Take the collateral captured earlier and go gather full details (no longer just a headline value)", "source": "evidenced"}, {"step": "Clarify collateral specifics with the customer (e.g. machinery type, year, engine, model)", "source": "evidenced"}, {"step": "Perform analysis on the collateral", "source": "evidenced"}, {"step": "For property/large owners, capture rent roll and tenancy management detail", "source": "evidenced"}, {"step": "For construction (apartments/large blocks), analyse the forecast — rent rolls and tenancy — to derive occupancy rate and predicted amounts and confirm sufficiency under downturn", "source": "evidenced"}, {"step": "Run CRE cashflow analysis and configure CRE/Tenancy templates and property/unit/lease records", "source": "inferred", "note": "Standard CRE & Tenancy Management behaviour per Community; SME to confirm Raiffeisen CRE config"}], "common_integrations": [], "community_articles": [{"title": "How to Use Commercial Real Estate Analysis (CRE)", "url": "https://ncino.my.site.com/s/article/HowtoUseCommercialRealEstateAnalysisCRE202501"}, {"title": "How to Configure Commercial Real Estate (CRE) - PART ONE", "url": "https://ncino.my.site.com/s/article/HowtoConfigureCommercialRealEstateCREPARTONE"}, {"title": "How to Use Tenancy Management", "url": "https://ncino.my.site.com/s/article/HowtoUseTenancyManagement"}, {"title": "How to Use CRE Cashflow Analysis", "url": "https://ncino.my.site.com/s/article/HowToUseCRECashflowAnalysis"}]},
  303: {"description": "Reviewing the customer's exposure using nCino's exposure management system, which captures all current exposure the customer has with the bank and can also capture external debt. The analyst reviews current exposure versus the proposed exposure of the new deal, checking it won't push the customer into a 'weird range' such as tier-one capital reporting, and that the overall exposure makes sense for what the bank is willing to be exposed to. This is one of the inputs that must be summarised up into the credit memo. Links to the heat map box 'Review Exposure' (Exposure).", "roles": ["Credit Analyst (primary)", "Underwriter (credit analyst more common in Europe)"], "process_steps": [{"step": "Open nCino's exposure management system showing all current exposure with the bank", "source": "evidenced"}, {"step": "Capture external debt (exposure held outside the bank)", "source": "evidenced"}, {"step": "Compare current exposure against the proposed exposure of the new deal", "source": "evidenced"}, {"step": "Check the deal won't push the customer into a problematic range (e.g. tier-one capital reporting) and that exposure is within the bank's appetite", "source": "evidenced"}, {"step": "Summarise the exposure review into the credit memo", "source": "evidenced"}, {"step": "Configure exposure aggregation (relationship/household roll-up, exposure types and limits)", "source": "inferred", "note": "Standard Total Exposure / Relationship Exposure behaviour per Community; SME to confirm Raiffeisen exposure config"}], "common_integrations": [], "community_articles": [{"title": "How to Configure Total Exposure", "url": "https://ncino.my.site.com/s/article/HowtoConfigureTotalExposure"}, {"title": "How to Use Total Exposure", "url": "https://ncino.my.site.com/s/article/HowtoUseTotalExposure"}, {"title": "How to Configure Relationship Exposure and Collateral", "url": "https://ncino.my.site.com/s/article/HowtoConfigureRelationshipExposureandCollateral"}, {"title": "How to Use Relationship Exposure and Collateral", "url": "https://ncino.my.site.com/s/article/HowtoUseRelationshipExposureandCollateral"}]},
  304: {"description": "Running the risk rating once all the inputs (exposure, collateral coverages, financials, fees) are in place. View exposure and risk rating are done by a credit analyst or underwriter (credit analyst more common in Europe). Risk rating can be simple — some banks use external parties to provide ratings — but most banks have their own models. The rating classifies the customer with a numerical or alphabetical value (the risk profile), typically resulting in a probability of default, via a calculation unique to each bank. Larger institutions typically don't use nCino for this, but nCino has a basic risk rating engine to calculate some details. Links to the heat map box 'Run Risk Rating' (Risk Rating engine).", "roles": ["Credit Analyst (primary, more common in Europe)", "Underwriter"], "process_steps": [{"step": "Assemble the inputs: exposure, collateral coverages, financials and fees", "source": "evidenced"}, {"step": "Run the risk rating (own model, or an external party providing ratings)", "source": "evidenced"}, {"step": "Classify the customer with a numerical or alphabetical risk value (risk profile)", "source": "evidenced"}, {"step": "Derive a probability of default via the bank's unique calculation", "source": "evidenced"}, {"step": "Use nCino's basic risk rating engine where the bank rates within nCino (larger institutions may rate externally)", "source": "evidenced"}, {"step": "Configure risk rating models, scorecards and grade scales in nCino", "source": "inferred", "note": "Standard Risk Rating config per Community; SME to confirm Raiffeisen model(s) / whether rating is done in nCino"}], "common_integrations": ["External rating parties"], "community_articles": [{"title": "How to Configure Risk Rating", "url": "https://ncino.my.site.com/s/article/HowtoConfigureRiskRating"}, {"title": "How to Use Risk Rating", "url": "https://ncino.my.site.com/s/article/HowtoUseRiskRating"}]},
  305: {"description": "Capturing and mitigating policy exceptions before the credit memo is started. Banks hold a credit policy document defining what/how they lend and what they don't lend to; sometimes a deal breaches that policy (e.g. they may not normally fund oil and gas, but a very lucrative deal warrants an exception). The user captures a policy exception within nCino along with the mitigation reason, so that everyone is aware before a decision is made that the policy is being breached and what is being done to mitigate it. Links to the heat map box 'Mitigate Policy Exceptions' (Policy Exceptions).", "roles": ["Credit Analyst (implied — underwriting actor)"], "process_steps": [{"step": "Reference the bank's credit policy (what/how it lends, what it won't lend to)", "source": "evidenced"}, {"step": "Identify where the deal is an exception to that policy", "source": "evidenced"}, {"step": "Capture a policy exception record within nCino", "source": "evidenced"}, {"step": "Capture the associated mitigation reason", "source": "evidenced"}, {"step": "Surface the exception so decision-makers see the breach and the mitigation before deciding", "source": "evidenced"}, {"step": "Configure Policy Exception Templates, mitigation reasons, severity levels and permissions; link to the Credit Memo", "source": "inferred", "note": "Standard Policy Exception Management config per Community; SME to confirm Raiffeisen templates"}], "common_integrations": [], "community_articles": [{"title": "Gold Standard: Automated Policy Exceptions", "url": "https://ncino.my.site.com/s/article/kAHHu000000XZShOAO"}, {"title": "How to Configure Policy Exception Management", "url": "https://ncino.my.site.com/s/article/HowtoConfigurePolicyExceptionManagement"}, {"title": "How to Use Policy Exception Management", "url": "https://ncino.my.site.com/s/article/HowtoUsePolicyExceptionManagement"}, {"title": "How to Configure Automated Policy Exceptions", "url": "https://ncino.my.site.com/s/article/HowtoConfigureAutomatedPolicyExceptions"}, {"title": "How to Use Automated Policy Exceptions", "url": "https://ncino.my.site.com/s/article/HowtoUseAutomatedPolicyExceptions"}]},
  306: {"description": "A detailed review of covenants in underwriting before the deal is put forward. Covenants may have been added at the start by a relationship manager; here someone who understands covenants reviews them in detail to ensure they are enforceable by law and fair to the customer. Covenants are legally binding — the bank can take repercussive actions if they are not met — so they must be fair but also easy to track and maintain. This is typically a more experienced or senior credit analyst reviewing covenants that a less senior analyst may have captured earlier. Links to the heat map box 'Review Covenants' (Covenant Servicing).", "roles": ["Experienced / Senior Credit Analyst (primary reviewer)", "Relationship Manager (may have added covenants at the start)"], "process_steps": [{"step": "Take the covenants added earlier (often by the RM) into detailed review", "source": "evidenced"}, {"step": "Confirm each covenant is enforceable by law", "source": "evidenced"}, {"step": "Confirm each covenant is fair to the customer", "source": "evidenced"}, {"step": "Confirm covenants are easy to track and maintain (given they are legally binding)", "source": "evidenced"}, {"step": "Have a more senior person review covenants captured by a junior analyst before putting the deal forward", "source": "evidenced"}, {"step": "Configure covenant types/subtypes, frequencies and servicing setup", "source": "inferred", "note": "Standard Covenant Management & Servicing config per Community; SME to confirm Raiffeisen covenant library"}], "common_integrations": [], "community_articles": [{"title": "How to Use Covenant Management and Servicing", "url": "https://ncino.my.site.com/s/article/HowtoUseCovenantManagementandServicing"}, {"title": "How to Configure Covenant Management & Servicing: Required Configuration", "url": "https://ncino.my.site.com/s/article/HowtoConfigureCovenantManagementandServicingRequiredConfiguration"}, {"title": "How to Configure Covenant Management & Servicing: Additional Configuration", "url": "https://ncino.my.site.com/s/article/HowtoConfigureCovenantManagementandServicingAdditionalConfiguration"}, {"title": "How to Use Covenant Servicing Sync to Placeholders", "url": "https://ncino.my.site.com/s/article/HowtoUseCovenantServicingSynctoPlaceholders"}]},
  307: {"description": "The key stage in underwriting, where all the relevant information is assembled into an approval document — the credit memo — for a credit decision. Described as the biggest stage in underwriting and approval because it carries hard stops. The credit memo is a documented template nCino can generate (some banks use their own versions in external systems); it goes to the credit officer to review for approval, rejection or recommendation. Within it, each qualification and underwriting feature is its own section, plus background on the customer, the proposal, why it is creditworthy and commentary. The populated credit memo cannot be completed until all prior underwriting inputs (covenants, policy exceptions, risk rating, exposure, collateral and spreading) are done. Links to the heat map box 'Populate Credit Memo' (Credit Memo).", "roles": ["Credit Analyst (populates — implied)", "Credit Officer (reviews for approval/rejection/recommendation)"], "process_steps": [{"step": "Confirm all prior underwriting inputs are complete (spreading, collateral, exposure, risk rating, policy exceptions, covenants)", "source": "evidenced"}, {"step": "Assemble the credit memo template, with each qualification/underwriting feature as its own section", "source": "evidenced"}, {"step": "Add background on the customer, the proposal, why it is creditworthy, and commentary", "source": "evidenced"}, {"step": "Generate the credit memo document in nCino (or use the bank's external version)", "source": "evidenced"}, {"step": "Route the populated credit memo to the credit officer for approval / rejection / recommendation", "source": "evidenced"}, {"step": "Configure the Credit Memo template — sections, narrative fields, tables and data merges", "source": "inferred", "note": "Standard Credit Memo config per Community; SME to confirm Raiffeisen template sections"}], "common_integrations": ["External credit memo systems"], "community_articles": [{"title": "How to Configure Credit Memo", "url": "https://ncino.my.site.com/s/article/HowtoConfigureCreditMemo202504"}]},
  308: {"description": "Submitting the populated credit memo for approval, usually by the relationship manager or credit analyst. This step cannot occur until the credit memo is populated. A delegation of authority within the bank defines who can approve what; this is either automatically built into nCino (to route the approval) or a manual selection by the RM/credit analyst, and more than one approval can be required. Once submitted, nCino locks down the loan or deal from further editing so nothing can change while the approval is being considered. Links to the heat map box 'Submit for Approval' (Approval Process).", "roles": ["Relationship Manager (primary)", "Credit Analyst (primary)"], "process_steps": [{"step": "Confirm the credit memo is populated (hard prerequisite)", "source": "evidenced"}, {"step": "Determine the approver(s) per the bank's delegation of authority", "source": "evidenced"}, {"step": "Route the approval automatically via nCino, or select the approver(s) manually", "source": "evidenced"}, {"step": "Submit, potentially requiring more than one approval", "source": "evidenced"}, {"step": "nCino locks down the loan/deal from further editing while approval is considered", "source": "evidenced"}, {"step": "Configure approval processes, routing and delegated approvers", "source": "inferred", "note": "Standard Approvals config per Community (Gold Standard: Approval Process Designs); SME to confirm Raiffeisen DOA matrix"}], "common_integrations": [], "community_articles": [{"title": "How to Use Deal Management", "url": "https://ncino.my.site.com/s/article/HowtoUseDealManagement"}, {"title": "How to Configure Deal Management", "url": "https://ncino.my.site.com/s/article/HowtoConfigureDealManagement"}]},
  309: {"description": "Capturing details around anything that is not a covenant but is potentially a condition to funding (e.g. AML not yet completed but recommended before funds are released, or a valuation needed on a very specific asset such as a particular type of ship, on which the credit decision will stand). Conditions can be added by a relationship manager or credit analyst before approval, or as part of approval when the credit officer reviews the credit memo. The credit officer can define conditions subsequent to funding or conditions precedent to funding as part of their approval. Notably, the SME flags that the placement is questionable — conditions 'should probably come before the population of the credit memo' and live more in the review-credit-memo stage or just before the approved deal. Links to the heat map box 'Add Conditions' (Conditions).", "roles": ["Relationship Manager", "Credit Analyst", "Credit Officer (defines conditions precedent/subsequent as part of approval)"], "process_steps": [{"step": "Identify items that are not covenants but are conditions to funding (e.g. outstanding AML, a specific valuation)", "source": "evidenced"}, {"step": "Capture the condition in nCino (RM or credit analyst, before approval)", "source": "evidenced"}, {"step": "Alternatively capture conditions as part of approval when the credit officer reviews the credit memo", "source": "evidenced"}, {"step": "Credit officer defines conditions precedent to funding and/or conditions subsequent to funding", "source": "evidenced"}, {"step": "Configure condition types and link conditions to Smart Checklist for tracking", "source": "inferred", "note": "Standard Conditions / Smart Checklist behaviour per Community; SME to confirm Raiffeisen condition types"}], "common_integrations": [], "community_articles": [{"title": "How to Configure Conditions", "url": "https://ncino.my.site.com/s/article/HowtoConfigureConditions"}, {"title": "How to Use Conditions", "url": "https://ncino.my.site.com/s/article/HowtoUseConditions"}, {"title": "How to Configure Smart Checklist", "url": "https://ncino.my.site.com/s/article/HowtoConfigureSmartChecklist202602"}]},
  401: {"description": "The first activity in the Approval stage. Following submit-for-approval in underwriting, the loan and deal are locked down ('a very hard link between underwriting finishing and approval starting'). The credit officer, or any other verified approvers selected at submission, review the populated credit memo document to make a credit decision — i.e. whether to take the deal forward as an approval or not. Links to the heat map box 'Review Credit Memo — Credit Memo'.", "roles": ["Credit Officer (primary)", "Approver(s) — whoever was verified/selected at submit-for-approval"], "process_steps": [{"step": "Loan and deal are locked down at the underwriting-to-approval transition (hard link), preventing further edits", "source": "evidenced"}, {"step": "Credit officer / verified approvers open and review the credit memo document", "source": "evidenced"}, {"step": "Decide whether to turn the review into a credit decision (approve / refer / decline)", "source": "evidenced"}, {"step": "Add commentary or conditions to the credit memo as part of review (conditions can be defined here per feature 309)", "source": "inferred", "note": "Transcript 309 places conditions in the review-credit-memo stage; SME to confirm Raiffeisen approval routing"}], "common_integrations": [], "community_articles": [{"title": "How to Configure Credit Memo - 2025_04", "url": "https://ncino.my.site.com/s/article/HowtoConfigureCreditMemo202504"}, {"title": "Gold Standard: Approval Process Designs", "url": "https://ncino.my.site.com/s/article/kAHHu000000XZTDOA4"}]},
  402: {"description": "An alternative/parallel approval route within the Approval stage. Where the loan or deal is large enough that an individual approver is insufficient, the credit officer can refer it to a credit committee to approve rather than a single approver. The credit officer can escalate for committee approval if needed, though typically approvers know their limits so referral is usually decided up front at submit-for-approval rather than escalated later. Review credit memo (401) and refer to credit committee operate together and depend on who was selected at submission. Links to the heat map box 'Refer to Credit Committee — Credit Committee'.", "roles": ["Credit Officer (escalates/refers)", "Credit Committee (approving body)"], "process_steps": [{"step": "Identify the loan/deal is large enough to need committee rather than individual approval", "source": "evidenced"}, {"step": "Review the credit memo and refer it to the credit committee (the two are linked)", "source": "evidenced"}, {"step": "Credit officer can escalate for approval if needed, though limits are usually known up front so referral is set at submit-for-approval", "source": "evidenced"}, {"step": "Committee records its decision through the approval process, which then proceeds the deal forward or back", "source": "inferred", "note": "Standard nCino approval-routing behaviour; SME to confirm how Raiffeisen models committee approval (e.g. approval process / matrix)"}], "common_integrations": [], "community_articles": [{"title": "Gold Standard: Approval Process Designs", "url": "https://ncino.my.site.com/s/article/kAHHu000000XZTDOA4"}]},
  403: {"description": "The happy-path decision point in the Approval stage. If the deal is creditworthy, the credit officer makes the decision in nCino by clicking the approve button, which proceeds the deal forward into the Processing stage. Links to the heat map box 'Approve Deal — Approval Process'.", "roles": ["Credit Officer (primary, makes the decision)"], "process_steps": [{"step": "Credit officer judges the deal creditworthy", "source": "evidenced"}, {"step": "Make the decision in nCino by clicking the approve button", "source": "evidenced"}, {"step": "Approval proceeds the deal forward to the Processing stage", "source": "evidenced"}, {"step": "If multiple approvals were required, each approver completes their step before the deal fully advances", "source": "inferred", "note": "Transcript 308 notes more than one approval can be required; SME to confirm Raiffeisen approval chain"}], "common_integrations": [], "community_articles": [{"title": "Gold Standard: Approval Process Designs", "url": "https://ncino.my.site.com/s/article/kAHHu000000XZTDOA4"}]},
  404: {"description": "The unhappy-path outcome in the Approval stage, handled through Adverse Actions: the loan or deal is not proceeding and the rationale is captured. Two distinct routes exist — a bank decline (credit officer says no, or will only proceed subject to conditions) and a customer withdrawal (a separate process where the customer chooses not to continue). Importantly, a credit officer's rejection is NOT an automatic declination: the credit officer may reject conditions or require more collateral, after which the relationship manager communicates with the customer, who can accept it or try to redo the deal. The deal only moves to Complete on a formal decline or withdrawal — which is why the withdrawal/decline action is kept with the relationship manager or credit analyst rather than the credit officer. Links to the heat map box 'Decline/Withdraw Deal — Adverse Actions'.", "roles": ["Relationship Manager (records withdrawal/decline, communicates to customer)", "Credit Analyst (records withdrawal/decline)", "Credit Officer (rejects/sets conditions, but does not formally move to Complete)"], "process_steps": [{"step": "Determine the loan/deal is not proceeding (bank decline or customer withdrawal)", "source": "evidenced"}, {"step": "Capture the adverse action and its rationale in nCino", "source": "evidenced"}, {"step": "Bank decline: credit officer says no, or will only proceed subject to specific conditions", "source": "evidenced"}, {"step": "Customer withdrawal handled as a separate process", "source": "evidenced"}, {"step": "A credit officer rejection is not an automatic declination — RM communicates to customer, who can accept or redo the deal", "source": "evidenced"}, {"step": "On a formal decline or withdrawal, the deal moves to Complete; the action is owned by RM/credit analyst, not the credit officer", "source": "evidenced"}], "common_integrations": [], "community_articles": [{"title": "How to Use Adverse Action", "url": "https://ncino.my.site.com/s/article/HowtoUseAdverseAction"}, {"title": "How to Configure Adverse Action", "url": "https://ncino.my.site.com/s/article/HowtoConfigureAdverseAction"}]},
  405: {"description": "The document-generation step on the unhappy path. When a deal is declined or withdrawn, specific documentation explaining why it was rejected can be generated automatically from nCino via document generation. The generated declination document captures the reasons recorded in nCino (from the adverse action, 404) and can be sent to the customer and/or kept internally. This can happen at any time; it is the same DocGen capability used elsewhere (e.g. 213, 601). Links to the heat map box 'Generate Declination Letter & Other Docs — DocGen / FormsGen'.", "roles": [], "process_steps": [{"step": "A decline or withdrawal occurs (adverse action recorded, 404)", "source": "evidenced"}, {"step": "Generate the specific declination documentation automatically from nCino (document generation)", "source": "evidenced"}, {"step": "Document captures the rejection reasons from what was put into nCino", "source": "evidenced"}, {"step": "Send the document to the customer and/or retain it internally", "source": "evidenced"}, {"step": "Generation uses a standardised template with variables, as with other DocGen", "source": "inferred", "note": "Consistent with DocGen described in 213/601; SME to confirm declination template content for Raiffeisen"}], "common_integrations": [], "community_articles": [{"title": "How to Use nCinos Document Generation", "url": "https://ncino.my.site.com/s/article/HowtoUsenCinosDocumentGeneration"}, {"title": "How to Configure nCinos Document Generation", "url": "https://ncino.my.site.com/s/article/HowtoConfigurenCinosDocumentGeneration"}, {"title": "How to Use Form Generation", "url": "https://ncino.my.site.com/s/article/HowtoUseFormGeneration"}, {"title": "How to Configure Form Generation - Required Configuration", "url": "https://ncino.my.site.com/s/article/HowtoConfigureFormGeneration"}, {"title": "How to Configure HTML Form Generation", "url": "https://ncino.my.site.com/s/article/HowtoConfigureHTMLFormGeneration"}]},
  501: {"description": "Once the credit officer has approved the deal it moves into the Processing stage, where the relationship manager or an operations user picks up the approved deal, reviews the approval and starts the next steps. One of the first of those is ordering third party reports — typically valuations and certifications, and potentially requests for additional information about the customer. Links to the heat map box 'Order 3rd Party Reports'.", "roles": ["Relationship Manager (primary, picks up approved deal)", "Operations user (primary, picks up approved deal)", "Credit Officer (upstream — approved the deal)"], "process_steps": [{"step": "Credit officer approves the deal, moving it into the Processing stage", "source": "evidenced"}, {"step": "Relationship manager or operations user picks up the approved deal and reviews the approval", "source": "evidenced"}, {"step": "Order third party reports — typically valuations and certifications", "source": "evidenced"}, {"step": "Request additional information about the customer where required", "source": "evidenced"}, {"step": "Select the report/service provider and submit the order via the third-party integration", "source": "inferred", "note": "Standard nCino third-party report ordering; SME to confirm providers and integration for Raiffeisen"}, {"step": "Track report status and receive results back against the deal/loan", "source": "inferred", "note": "Standard lifecycle; SME to confirm"}], "common_integrations": [], "community_articles": [{"title": "How to Configure Third Parties and Service Management", "url": "https://ncino.my.site.com/s/article/HowtoConfigureThirdPartiesandServiceManagement"}]},
  502: {"description": "After approval there may be additional fees required — for example specific valuation fees, or extra handling/administration fees. Alternatively the credit analyst or credit officer may not have captured the fees correctly, so it falls to the operations user to add the correct fees to the loan. The intent is to make sure everything is correct before proceeding, capturing those fees either prior to or post funding. Links to the heat map box 'Add Fees to Loan'.", "roles": ["Operations user (primary, adds/corrects fees)", "Credit Analyst (upstream — may have captured fees)", "Credit Officer (upstream — may have captured fees)"], "process_steps": [{"step": "After approval, identify additional fees that are required (e.g. valuation fees, handling/administration fees)", "source": "evidenced"}, {"step": "Review fees captured earlier by the credit analyst/credit officer and correct them where they were not captured correctly", "source": "evidenced"}, {"step": "Operations user adds the correct fees to the loan", "source": "evidenced"}, {"step": "Capture the fees prior to funding or post funding, ensuring everything is correct before proceeding", "source": "evidenced"}, {"step": "Select fee type and link the fee to the appropriate loan/product package record via Fee Management", "source": "inferred", "note": "Standard nCino Fee Management behaviour; SME to confirm fee types and configuration for Raiffeisen"}], "common_integrations": [], "community_articles": [{"title": "How to Use Fee Management for Commercial, Retail, and Small Business Loans", "url": "https://ncino.my.site.com/s/article/HowtoUseFeeManagementforCommercialRetailandSmallBusinessLoans"}, {"title": "How to Configure Fee Management", "url": "https://ncino.my.site.com/s/article/HowtoConfigureFeeManagement"}, {"title": "How to Configure Auto-Applied Fees", "url": "https://ncino.my.site.com/s/article/HowtoConfigureAutoAppliedFees"}, {"title": "How to Use Fee Administration", "url": "https://ncino.my.site.com/s/article/HowtoUseFeeAdministration"}]},
  503: {"description": "The credit officer may approve the deal subject to conditions, so the user needs to review what the credit officer listed in their approval and capture/action those aspects as they go through. NB: the transcript describes reviewing the credit officer's approval and conditions, not separately reviewing and approving the third-party reports as a distinct 'Approval Process' step — only adjacent coverage exists for this box. Links to the heat map box 'Review/Approve Reports'.", "roles": ["Credit Officer (upstream — approves subject to conditions)", "Relationship Manager / Operations user (implied — reviews and captures the conditions; not explicitly named for this step)"], "process_steps": [{"step": "Credit officer approves subject to condition", "source": "evidenced"}, {"step": "Review what the credit officer listed out in their approval", "source": "evidenced"}, {"step": "Capture/action the conditions as they go through", "source": "evidenced"}, {"step": "Review and approve the returned third-party reports (e.g. valuations) before proceeding", "source": "inferred", "note": "Box is labelled 'Review/Approve Reports — Approval Process'; transcript does not describe report review/approval as a distinct step. SME to confirm whether an Approval Process is configured for reports"}], "common_integrations": [], "community_articles": [{"title": "Gold Standard: Approval Process Designs", "url": "https://ncino.my.site.com/s/article/kAHHu000000XZTDOA4"}, {"title": "How to Configure Conditions", "url": "https://ncino.my.site.com/s/article/HowtoConfigureConditions"}]},
  504: {"description": "A 'slightly less happy path': a post-approval change memo can be raised at any time between approval and booking when there has been a fundamental change to a deal the credit officer already approved — common examples being a change in loan amount, a collateral valuation that is no longer enough, or the customer changing their mind. Because the loan record is locked down after approval, materially changing something is a formal process: the change memo acts as an unlock mechanism that moves the loan back into the underwriting stage, opens it for editing, then resubmits it for approval to re-seek the credit officer's sign-off. It does not always happen, but it is a mechanism available in nCino. Links to the heat map box 'Post Approval Change'.", "roles": ["Credit Officer (re-seeks / re-grants approval)", "User raising the change memo (not explicitly named — implied relationship manager or operations)"], "process_steps": [{"step": "Identify a fundamental/material change after approval (e.g. change in loan amount, insufficient collateral valuation, customer changed their mind)", "source": "evidenced"}, {"step": "Raise a post-approval change memo (can occur at any time between approval and booking)", "source": "evidenced"}, {"step": "Change memo acts as an unlock process — moves the locked-down loan back into the underwriting stage and opens it for editing", "source": "evidenced"}, {"step": "Make the required material change to the loan", "source": "evidenced"}, {"step": "Resubmit for approval to re-seek the credit officer's approval", "source": "evidenced"}, {"step": "Document the reason/justification for the change on the memo for audit", "source": "inferred", "note": "Standard nCino memo/change-control practice; SME to confirm for Raiffeisen"}], "common_integrations": [], "community_articles": [{"title": "How to Use Memo", "url": "https://ncino.my.site.com/s/article/HowtoUseMemo"}, {"title": "How to Configure Memo", "url": "https://ncino.my.site.com/s/article/HowtoConfigureMemo"}]},
  505: {"description": "Document Manager is again used here, against the loan and the product package or the customer. Now that things have been approved, more documents may be captured and more information required, so this provides the ability to store documents at the Processing stage. Links to the heat map box 'Collect & Store Documents'. (Same Document Manager capability used earlier in the lifecycle, reapplied in Processing.)", "roles": [], "process_steps": [{"step": "Use Document Manager against the loan, the product package or the customer", "source": "evidenced"}, {"step": "Capture additional documents now that the deal has been approved", "source": "evidenced"}, {"step": "Store documents and request more information where required", "source": "evidenced"}, {"step": "Classify/categorise documents and link them to the correct record(s) via Document Manager", "source": "inferred", "note": "Standard Document Manager behaviour; SME to confirm document types/checklist for Raiffeisen"}], "common_integrations": [], "community_articles": [{"title": "Gold Standard: Document Manager", "url": "https://ncino.my.site.com/s/article/kAHHu000000XZTEOA4"}, {"title": "How to Use Document Manager", "url": "https://ncino.my.site.com/s/article/HowtoUseDocumentManager"}, {"title": "How to Configure Document Manager", "url": "https://ncino.my.site.com/s/article/HowtoConfigureDocumentManager"}]},
  601: {"description": "After processing (which is not always a hard stage — some banks go straight into document preparation), the user generates the offer documents or contracts for the customer based on all the information captured earlier. Document preparation is explicitly NOT legal contract preparation; it is the generation of offer documents/contracts from prior data, which is why the loan remains locked down. Generation can be done within nCino (DocGen / Form Generation), but larger banks may use a third-party document generation system via an integration. Links to the heat map box 'Generate Offer Letter & Other Docs' (DocGen / FormsGen).", "roles": [], "process_steps": [{"step": "Confirm processing is complete and the credit officer's approval and any conditions are in order before preparing documents", "source": "evidenced", "note": "Transcript frames doc prep as the step after ensuring approval was given correctly and conditions captured"}, {"step": "Generate the offer documents / contracts for the customer based on all previously provided information", "source": "evidenced"}, {"step": "Generate within nCino via DocGen, or via a third-party document generation system through an integration (larger banks)", "source": "evidenced"}, {"step": "Keep the loan/deal locked down so the generated documents reflect the approved, unchanged data", "source": "evidenced"}, {"step": "Select the relevant standardised template(s) and merge in variables (e.g. customer name, product name, amount, conditions)", "source": "inferred", "note": "Standard nCino DocGen behaviour per feature 213; SME to confirm Raiffeisen templates and merge fields"}, {"step": "Review generated output before distribution", "source": "inferred", "note": "SME to confirm review/4-eyes step for offer docs"}], "common_integrations": ["Third-party document generation system"], "community_articles": [{"title": "How to Use nCino's Document Generation", "url": "https://ncino.my.site.com/s/article/HowtoUsenCinosDocumentGeneration"}, {"title": "How to Configure nCino's Document Generation", "url": "https://ncino.my.site.com/s/article/HowtoConfigurenCinosDocumentGeneration"}, {"title": "How to Use Form Generation", "url": "https://ncino.my.site.com/s/article/HowtoUseFormGeneration"}, {"title": "How to Configure Form Generation - Required Configuration", "url": "https://ncino.my.site.com/s/article/HowtoConfigureFormGeneration"}, {"title": "How to Configure HTML Form Generation", "url": "https://ncino.my.site.com/s/article/HowtoConfigureHTMLFormGeneration"}, {"title": "How to Configure Automated Form Generation", "url": "https://ncino.my.site.com/s/article/HowtoConfigureAutomatedFormGeneration"}]},
  602: {"description": "Once the offer documents are generated, the user works through which documents go to which customer (borrower, co-borrower, guarantor), generates the different versions, captures customer details for emails and identifies who needs to sign, then sends the documents out — usually electronically, though some still use post. E-sign is the most typical route, but documents can also be printed and given to customers. nCino does not have a native e-signing capability: signing is done either via a third-party integration or by wet ink, with wet-ink documents scanned back up and stored on nCino. Links to the heat map box 'Sign Documents' (Signicat). NB: the heat map subtitle names 'Signicat' as the e-sign integration, but the transcript describes third-party e-signing generically and does not name Signicat.", "roles": [], "process_steps": [{"step": "Determine which documents need to go to which customer (borrower, co-borrower, guarantor)", "source": "evidenced"}, {"step": "Generate the different versions of the documents per recipient", "source": "evidenced"}, {"step": "Capture customer details for emails and identify who needs to sign", "source": "evidenced"}, {"step": "Send the documents out, usually electronically (e-sign) — some customers still use post", "source": "evidenced"}, {"step": "Sign via a third-party e-signing integration (nCino has no native e-sign), or sign by wet ink", "source": "evidenced"}, {"step": "For wet-ink signing, scan the signed documents back up and store them on nCino", "source": "evidenced"}, {"step": "Configure the specific e-signature integration (Signicat per heat map subtitle) and recipient/signing routing", "source": "inferred", "note": "Signicat is named on the heat map but NOT in the transcript; SME to confirm the e-sign provider and routing config for Raiffeisen"}], "common_integrations": ["Third-party e-signature provider"], "community_articles": [{"title": "How to Use E-Signature for Document Manager", "url": "https://ncino.my.site.com/s/article/HowtoUseESignatureforDocumentManager"}, {"title": "How to Configure E-Signature for Online Application", "url": "https://ncino.my.site.com/s/article/HowtoConfigureESignatureforOnlineApplication"}]},
  603: {"description": "After signing, the signed documents are stored back on nCino. These signed documents are a hard stop: the deal cannot proceed into final review until they have been put through. This is the doc-preparation instance of the Document Manager repository (the same Document Manager feature used to collect/store documents earlier in the lifecycle, e.g. features 212 and 505). Links to the heat map box 'Collect & Store Documents' (Document Manager).", "roles": [], "process_steps": [{"step": "Store the signed documents back on nCino (in the Document Manager)", "source": "evidenced"}, {"step": "Treat the signed documents as a hard stop — do not proceed into final review until they are put through", "source": "evidenced"}, {"step": "Place the signed documents against the relevant record (deal, product package, loan or customer) using the configured document types/placeholders", "source": "inferred", "note": "Standard Document Manager behaviour per feature 212; SME to confirm Raiffeisen document types and placeholder setup"}, {"step": "Apply any 4-eyes checks on the stored documents where required", "source": "inferred", "note": "Transcript notes optional 4-eyes checks on Document Manager docs (feature 212); SME to confirm for signed docs"}], "common_integrations": [], "community_articles": [{"title": "Gold Standard: Document Manager", "url": "https://ncino.my.site.com/s/article/kAHHu000000XZTEOA4"}, {"title": "How to Use Document Manager", "url": "https://ncino.my.site.com/s/article/HowtoUseDocumentManager"}, {"title": "How to Configure Document Manager", "url": "https://ncino.my.site.com/s/article/HowtoConfigureDocumentManager"}]},
  701: {"description": "In final review, before funds are transferred, the bank performs its last checks. Any fees that were required prior to funding (e.g. valuation fees) must be paid and noted as collected. nCino is used to record/note that those fees have been collected via fee management; the actual payment of the fee is not performed in nCino (typically handled by the core system or a bank transfer). Links to the heat map box 'Collect Fees' (Fee Management).", "roles": [], "process_steps": [{"step": "As part of final pre-funding checks, identify fees that were required prior to funding (e.g. valuation fees)", "source": "evidenced"}, {"step": "Ensure those fees are collected/paid", "source": "evidenced"}, {"step": "Note/record the fee as collected (complete) on nCino via fee management", "source": "evidenced"}, {"step": "Actual payment of the fee occurs outside nCino (core system or bank transfer), not in nCino", "source": "evidenced"}, {"step": "Open the loan/facility fee management, mark the relevant fee record status as collected/paid and capture the collection date", "source": "inferred", "note": "Standard nCino fee status handling; SME to confirm Raiffeisen fee statuses and collection fields"}], "common_integrations": ["Core banking system / bank transfer"], "community_articles": [{"title": "How to Use Fee Management for Commercial, Retail, and Small Business Loans", "url": "https://ncino.my.site.com/s/article/HowtoUseFeeManagementforCommercialRetailandSmallBusinessLoans"}, {"title": "How to Configure Fee Management", "url": "https://ncino.my.site.com/s/article/HowtoConfigureFeeManagement"}, {"title": "How to Configure Auto-Applied Fees", "url": "https://ncino.my.site.com/s/article/HowtoConfigureAutoAppliedFees"}, {"title": "How to Use Fee Administration", "url": "https://ncino.my.site.com/s/article/HowtoUseFeeAdministration"}]},
  702: {"description": "In final review the bank ensures its collateral is secured and that it holds all the relevant information for that collateral. This includes capturing a lien against the collateral (asserting first/priority rights to claim against it). Different lien positions can be recorded, and all this information is captured in nCino — but the lien usually has to be registered on a third-party government register, which in turn provides information about other banks that may hold an interest in the collateral and/or a unique registration ID, to confirm everything required is in place. Links to the heat map box 'Collateral Management'.", "roles": [], "process_steps": [{"step": "Confirm the collateral securing the loan is secured and all relevant collateral information is held", "source": "evidenced"}, {"step": "Capture a lien against the collateral, asserting first rights to claim against it", "source": "evidenced"}, {"step": "Record the lien position (different lien positions are possible)", "source": "evidenced"}, {"step": "Register the lien on the third-party government register", "source": "evidenced", "note": "Transcript: usually registered on an external government register"}, {"step": "Capture the register's returned information (other banks with an interest, unique ID) back in nCino", "source": "evidenced"}, {"step": "Verify lien/collateral perfection and required documentation are complete before funding", "source": "inferred", "note": "Standard pre-funding collateral perfection check; SME to confirm Raiffeisen lien fields and register integration"}], "common_integrations": ["Third-party government collateral/lien register"], "community_articles": [{"title": "Gold Standard: Collateral Management", "url": "https://ncino.my.site.com/s/article/kAHHu000000XZTyOAO"}, {"title": "How to Use Collateral Management", "url": "https://ncino.my.site.com/s/article/HowtoUseCollateralManagement"}, {"title": "How to Configure Collateral Management - PART ONE - 2025_09", "url": "https://ncino.my.site.com/s/article/HowtoConfigureCollateralManagementPARTONE202509"}, {"title": "How to Use Enhanced Collateral Management - Spring 2022", "url": "https://ncino.my.site.com/s/article/HowtoUseEnhancedCollateralManagementSpring2022"}, {"title": "How to Configure Enhanced Collateral Management - PART ONE - Spring 2023", "url": "https://ncino.my.site.com/s/article/HowtoConfigureEnhancedCollateralManagementPARTONESpring2023"}]},
  703: {"description": "Once collateral is secured (all liens registered), every document is in place and fees are collected, the bank runs its loan closing checks. These can be performed either as a document-manager check or as conditions; this box is the Document Manager variant. The closing checks can be run as a checklist — nCino's Smart Checklist can be used — to capture the checks that must be done (e.g. ensuring the credit decision is done and understood). Anything that is a manual operational risk typically has a checklist to mitigate closing risk. Links to the heat map box 'Loan Closing Checks (Document Manager)'.", "roles": [], "process_steps": [{"step": "Confirm collateral is secured, all liens registered, every document stored and fees collected", "source": "evidenced"}, {"step": "Run the loan closing checks (this box: as a document-manager check)", "source": "evidenced"}, {"step": "Use a checklist (Smart Checklist available in nCino) to capture the checks required", "source": "evidenced"}, {"step": "Check items such as ensuring the credit decision is done and understood", "source": "evidenced"}, {"step": "Use checklists to mitigate manual operational/closing risk", "source": "evidenced"}, {"step": "Configure closing-check document types/placeholders in Document Manager so required closing docs are verified present", "source": "inferred", "note": "Document-Manager-flavoured closing verification; SME to confirm Raiffeisen closing checklist/doc setup"}], "common_integrations": [], "community_articles": [{"title": "How to Use Smart Checklist", "url": "https://ncino.my.site.com/s/article/HowtoUseSmartChecklist"}, {"title": "How to Configure Smart Checklist", "url": "https://ncino.my.site.com/s/article/HowtoConfigureSmartChecklist"}, {"title": "How to Configure Document Manager Placeholders", "url": "https://ncino.my.site.com/s/article/HowtoConfigureDocumentManagerPlaceholders"}, {"title": "How to Configure Document Manager Permissions", "url": "https://ncino.my.site.com/s/article/HowtoConfigureDocumentManagerPermissions"}]},
  704: {"description": "The Conditions variant of the loan closing checks. Once collateral is secured (all liens registered), every document is in place and fees are collected, the bank runs its loan closing checks — these can be done either as a document-manager check or as conditions; this box is the Conditions variant. As with the other variants, the checks can be run as a checklist (Smart Checklist) to capture the operational items that must be completed before funding. Related to feature 309 (Add Conditions) and feature 705. Links to the heat map box 'Loan Closing Checks (Conditions)'.", "roles": [], "process_steps": [{"step": "Confirm collateral is secured, all liens registered, every document stored and fees collected", "source": "evidenced"}, {"step": "Run the loan closing checks (this box: as conditions)", "source": "evidenced"}, {"step": "Review/verify the conditions to funding are satisfied as part of closing", "source": "evidenced", "note": "Transcript states closing checks can be done 'as conditions'; ties to conditions captured earlier (309)"}, {"step": "Use a checklist (Smart Checklist) to capture and clear the closing items / conditions", "source": "evidenced"}, {"step": "Mark conditions precedent to funding as met before allowing the loan to progress", "source": "inferred", "note": "Standard nCino conditions-clearing behaviour; SME to confirm Raiffeisen condition types and gating"}], "common_integrations": [], "community_articles": [{"title": "How to Use Smart Checklist", "url": "https://ncino.my.site.com/s/article/HowtoUseSmartChecklist"}, {"title": "How to Configure Smart Checklist", "url": "https://ncino.my.site.com/s/article/HowtoConfigureSmartChecklist"}, {"title": "How to Configure Conditions", "url": "https://ncino.my.site.com/s/article/HowtoConfigureConditions"}]},
  705: {"description": "A third Loan Closing Checks box, subtitled 'Covenant Servicing / Management'. The transcript states loan closing checks can be done 'either as document manager or as conditions' and references the Smart Checklist, but it does not explicitly describe a covenant-servicing variant of the closing checks. The closest related coverage is that covenants are captured/reviewed earlier (211 in qualification, 306 in underwriting) and monitored/serviced later (802 covenant servicing in monitoring). This box appears to represent verifying covenant set-up/servicing readiness as part of closing, but that is not spelled out in the walkthrough. Links to the heat map box 'Loan Closing Checks (Covenant Servicing)'. CONCEPT/PARTIAL — SME confirmation required.", "roles": [], "process_steps": [{"step": "As part of loan closing checks, the bank runs checks 'either as document manager or as conditions' and may use the Smart Checklist", "source": "evidenced", "note": "General closing-check statement; the covenant-servicing variant is NOT explicitly described"}, {"step": "Verify covenants are correctly set up / ready for servicing before the loan is funded and handed to monitoring", "source": "inferred", "note": "Inferred from the box subtitle and from covenants being captured (211), reviewed (306) and serviced (802); SME to confirm what the covenant-servicing closing check entails"}, {"step": "Confirm covenant testing frequencies and evidence requirements are configured ahead of monitoring", "source": "inferred", "note": "Inferred linkage to covenant servicing/monitoring; SME to confirm"}], "common_integrations": [], "community_articles": [{"title": "How to Use Covenant Management and Servicing", "url": "https://ncino.my.site.com/s/article/HowtoUseCovenantManagementandServicing"}, {"title": "How to Configure Covenant Management & Servicing: Required Configuration", "url": "https://ncino.my.site.com/s/article/HowtoConfigureCovenantManagementandServicingRequiredConfiguration"}, {"title": "How to Configure Covenant Management & Servicing: Additional Configuration", "url": "https://ncino.my.site.com/s/article/HowtoConfigureCovenantManagementandServicingAdditionalConfiguration"}, {"title": "How to Use Covenant Servicing Sync to Placeholders", "url": "https://ncino.my.site.com/s/article/HowtoUseCovenantServicingSynctoPlaceholders"}, {"title": "How to Configure Automated Covenant Testing", "url": "https://ncino.my.site.com/s/article/HowtoConfigureAutomatedCovenantTesting"}, {"title": "How to Use Automated Covenant Testing", "url": "https://ncino.my.site.com/s/article/HowtoUseAutomatedCovenantTesting"}]},
  706: {"description": "The last three final-review boxes sit under Construction Loan Administration, which is only applicable for construction loans — if a loan is not a construction loan this area is not relevant and can be left out. For construction loans specifically, there may be a required budget and specific stage gates within the project-finance process: unless the defined stages are completed and evidence provided, the next stage of funding (draws and disbursements) will not be released. Links to the heat map box 'Construction Loan Administration'.", "roles": [], "process_steps": [{"step": "Determine the loan is a construction loan (this whole area only applies to construction loans; otherwise it can be left out)", "source": "evidenced"}, {"step": "Set up the construction loan administration with a specific budget as required", "source": "evidenced"}, {"step": "Define the specific stage gates for the project-finance process", "source": "evidenced"}, {"step": "Require evidence at each stage; do not release the next stage of funding (draws/disbursements) until the prior stage is completed and evidenced", "source": "evidenced"}, {"step": "Configure construction loan administration records linking budget (707) and draw/disbursement schedules (708)", "source": "inferred", "note": "Standard nCino Construction Loan Administration structure; SME to confirm Raiffeisen construction config"}], "common_integrations": [], "community_articles": [{"title": "How to Use Construction Loan Administration", "url": "https://ncino.my.site.com/s/article/HowtoUseConstructionLoanAdministration"}, {"title": "How to Configure Construction Loan Administration", "url": "https://ncino.my.site.com/s/article/HowtoConfigureConstructionLoanAdministration"}]},
  707: {"description": "The budgeting aspect of construction loan administration — the construction budget. Based on that budget, funds are released accordingly. The example in the transcript: machinery is given as part of the budget, the machinery work is done, and that information is pulled through. This sits within final review under construction loan administration. Links to the heat map box 'Budget'.", "roles": [], "process_steps": [{"step": "Create the construction budget for the construction loan", "source": "evidenced"}, {"step": "Use the budget as the basis for releasing funds accordingly", "source": "evidenced"}, {"step": "Track budget line items (e.g. machinery) as the work is performed and pull that information through", "source": "evidenced"}, {"step": "Reconcile actual spend / completed work against the budget before releasing the corresponding draw", "source": "inferred", "note": "Standard construction budget-to-draw reconciliation; SME to confirm Raiffeisen budget structure"}], "common_integrations": [], "community_articles": [{"title": "How to Use Construction Loan Administration", "url": "https://ncino.my.site.com/s/article/HowtoUseConstructionLoanAdministration"}, {"title": "How to Configure Construction Loan Administration", "url": "https://ncino.my.site.com/s/article/HowtoConfigureConstructionLoanAdministration"}]},
  708: {"description": "The draws and disbursements aspect of construction loan administration. For some loans all funds are simply issued to the customer or a line of credit is made available; other loans are funded based on different conditions. Where conditions apply, those conditions are captured and disbursement schedules are conducted — e.g. release 20% now, 40% once the building is airtight, and 60% on completion with certification. Putting that staged release through is the draws and disbursements function. Links to the heat map box 'Draws and Disbursements'.", "roles": [], "process_steps": [{"step": "Determine the funding approach: issue all funds / make a line of credit available, or fund based on conditions", "source": "evidenced"}, {"step": "Where conditions apply, capture those conditions", "source": "evidenced"}, {"step": "Conduct the disbursement schedules (e.g. 20% now, 40% on building airtight, 60% on completion with certification)", "source": "evidenced"}, {"step": "Put the staged release through as draws and disbursements as each condition/stage is met and evidenced", "source": "evidenced"}, {"step": "Validate the prior construction stage gate (706) and budget (707) before releasing each draw", "source": "inferred", "note": "Inferred linkage to stage gates/budget; SME to confirm Raiffeisen disbursement controls"}], "common_integrations": [], "community_articles": [{"title": "How to Use Construction Loan Administration", "url": "https://ncino.my.site.com/s/article/HowtoUseConstructionLoanAdministration"}, {"title": "How to Configure Construction Loan Administration", "url": "https://ncino.my.site.com/s/article/HowtoConfigureConstructionLoanAdministration"}]},
  801: {"description": "The point at which nCino, as the origination system, hands the booked loan over to the bank's core banking system. All the captured details (credit approval, signed documents, structure) are pushed into the core, which then manages the loan throughout its lifecycle with the customer; the funds are transferred and once the loan is live in the core the customer has their money. This is typically where nCino's role as an origination system ends and its role as a monitoring system begins. On the booking side this is the main point at which the origination process stops, performed by the booking specialist / operations specialist. Links to the heat map box 'Transfer of data from origination to core'. NB: the box subtitle names 'Finacle' as the core, but the transcript refers only to 'the core system' generically and does not name Finacle.", "roles": ["Booking specialist / operations specialist (primary)"], "process_steps": [{"step": "Take the fully approved, documented and signed loan record in nCino", "source": "evidenced"}, {"step": "Transfer / book all the loan information into the core banking system", "source": "evidenced"}, {"step": "Transfer the funds to the customer; once live in the core the customer has their funds", "source": "evidenced"}, {"step": "Core system takes over lifecycle management of the loan; nCino transitions from origination to monitoring", "source": "evidenced"}, {"step": "Booking is the main point at which origination stops on the booking side", "source": "evidenced"}, {"step": "Configure / use an integration that pushes the loan record from nCino to the named core (e.g. Finacle) and returns booking confirmation / account numbers", "source": "inferred", "note": "Standard nCino-to-core booking integration pattern; the specific core (Finacle) and the integration mechanism are not described in the transcript. SME to confirm."}], "common_integrations": ["Core banking system"], "community_articles": []},
  802: {"description": "The monitoring-stage activity where covenants captured earlier in the deal are evidenced and certified as compliant over the life of the loan. nCino provides a covenant servicing module where the details for each covenant are recorded and compliance is captured (typically on the recurring frequency — annual, semi-annual, monthly — set when the covenant was created). Links to the heat map box 'Covenants Monitoring — Covenant Servicing'.", "roles": [], "process_steps": [{"step": "Identify the covenants captured earlier that now require evidencing", "source": "evidenced"}, {"step": "Use the covenant servicing module to record covenant details and capture compliance evidence/certification", "source": "evidenced"}, {"step": "Mark each covenant as compliant (or not) for the relevant reporting period", "source": "evidenced"}, {"step": "Track upcoming covenant due dates and trigger reminders/tasks on the recurring frequency", "source": "inferred", "note": "Standard covenant servicing behaviour (and surfaced via Priority Manager); SME to confirm Raiffeisen frequencies and routing."}, {"step": "Record a breach and initiate downstream action when a covenant fails", "source": "inferred", "note": "Links to breach document generation (811); SME to confirm."}], "common_integrations": [], "community_articles": [{"title": "How to Use Covenant Management and Servicing", "url": "https://ncino.my.site.com/s/article/HowtoUseCovenantManagementandServicing"}, {"title": "How to Configure Covenant Management & Servicing: Required Configuration", "url": "https://ncino.my.site.com/s/article/HowtoConfigureCovenantManagementandServicingRequiredConfiguration"}, {"title": "How to Configure Covenant Management & Servicing: Additional Configuration", "url": "https://ncino.my.site.com/s/article/HowtoConfigureCovenantManagementandServicingAdditionalConfiguration"}, {"title": "How to Use Covenant Servicing Sync to Placeholders", "url": "https://ncino.my.site.com/s/article/HowtoUseCovenantServicingSynctoPlaceholders"}, {"title": "How to Configure Automated Covenant Testing", "url": "https://ncino.my.site.com/s/article/HowtoConfigureAutomatedCovenantTesting"}, {"title": "How to Use Automated Covenant Testing", "url": "https://ncino.my.site.com/s/article/HowtoUseAutomatedCovenantTesting"}]},
  803: {"description": "Where covenants are linked to financial figures, the customer's financials can be captured in nCino and covenant compliance tested automatically against that financial data, rather than relying on manual certification. Links to the heat map box 'Automated Covenant testing'.", "roles": [], "process_steps": [{"step": "Capture the customer's financials in nCino", "source": "evidenced"}, {"step": "For covenants linked to financials, run automated covenant testing against that financial data", "source": "evidenced"}, {"step": "Map covenant thresholds to spread/financial line items so tests can evaluate automatically", "source": "inferred", "note": "Standard automated covenant testing config; SME to confirm field mapping for Raiffeisen."}, {"step": "Surface pass/fail results and flag breaches for action", "source": "inferred", "note": "SME to confirm."}], "common_integrations": [], "community_articles": [{"title": "How to Use Automated Covenant Testing", "url": "https://ncino.my.site.com/s/article/HowtoUseAutomatedCovenantTesting"}, {"title": "How to Configure Automated Covenant Testing", "url": "https://ncino.my.site.com/s/article/HowtoConfigureAutomatedCovenantTesting"}]},
  804: {"description": "Within the periodic review, the credit analyst checks the customer's exposure, refreshes/obtains the customer's financials (spreads) and re-evaluates collateral to keep a current view of the bank's position. The heat map frames this as MI management and exposure levels driven off spreads and exposure data. Links to the heat map box 'MI Mgmt & Exposure Levels — Spreads & Exposure'. NB: the transcript covers spreads, exposure and financials within the review process but does not name a distinct 'MI management' function — closest adjacent coverage only.", "roles": ["Credit analyst (primary; performs the collateral, spreads and exposure / covenant testing within the review)"], "process_steps": [{"step": "As part of the review, check the customer's current exposure", "source": "evidenced"}, {"step": "Obtain/refresh the customer's financials (spreads)", "source": "evidenced"}, {"step": "Re-evaluate the collateral", "source": "evidenced"}, {"step": "Produce management information / monitor exposure levels across the portfolio from spreads and exposure data", "source": "inferred", "note": "Heat map labels this 'MI Mgmt'; the transcript does not name a distinct MI function. SME to confirm what MI management entails for Raiffeisen."}], "common_integrations": [], "community_articles": [{"title": "How to Configure Spreads - PART ONE", "url": "https://ncino.my.site.com/s/article/HowtoConfigureSpreadsPARTONE"}, {"title": "How to Use Spreads - PART ONE - 2025_05", "url": "https://ncino.my.site.com/s/article/HowtoUseSpreadsPARTONE202505"}, {"title": "How to Configure Spreads - PART TWO - 2025_09", "url": "https://ncino.my.site.com/s/article/HowtoConfigureSpreadsPARTTWO202509"}, {"title": "How to Use Spreads - PART TWO - 2025_02", "url": "https://ncino.my.site.com/s/article/HowtoUseSpreadsPARTTWO202502"}]},
  805: {"description": "Part of the periodic (annual) review: the collateral securing the loan is re-evaluated to confirm it is still sufficient and the customer remains creditworthy with nothing at risk of impacting repayments. Sits alongside checking exposure and obtaining the customer's financials within the review cycle. Links to the heat map box 'Re-evaluate Collateral'.", "roles": ["Credit analyst (collateral, spreads and exposure within the review are usually done by a credit analyst)"], "process_steps": [{"step": "On the periodic (annual) review, revisit the collateral securing the loan", "source": "evidenced"}, {"step": "Re-evaluate the collateral value as part of confirming continued creditworthiness", "source": "evidenced"}, {"step": "Check exposure and obtain the customer's financials alongside the collateral re-evaluation", "source": "evidenced"}, {"step": "Order an updated valuation where a refreshed market value is required", "source": "inferred", "note": "Standard nCino collateral revaluation step; SME to confirm trigger and valuation source."}], "common_integrations": [], "community_articles": [{"title": "How to Configure Collateral Valuation", "url": "https://ncino.my.site.com/s/article/HowtoConfigureCollateralValuation"}, {"title": "Gold Standard: Collateral Management", "url": "https://ncino.my.site.com/s/article/kAHHu000000XZTyOAO"}]},
  806: {"description": "The periodic review process — typically annual — to re-assess whether the customer is still creditworthy. The review pulls together the collateral re-evaluation, spreads and exposure / covenant testing (usually performed by a credit analyst) and requires an approval. Review approvals can be routed through nCino similar to the credit approval process, with the option to self-approve where nothing is material, and can use different approval routings to the actual credit routings. Reviews can be manual or automated (see Agentic Reviews, 807). Links to the heat map box 'Carry out Reviews'.", "roles": ["Credit analyst (carries out the review components)", "Approver (review approvals; can be self-approval where immaterial)"], "process_steps": [{"step": "Initiate the periodic (annual) review of the customer", "source": "evidenced"}, {"step": "Pull together the collateral, spreads and exposure / covenant testing inputs (usually done by a credit analyst)", "source": "evidenced"}, {"step": "Submit the review for approval", "source": "evidenced"}, {"step": "Route review approvals through nCino, using approval routings that can differ from the credit routings", "source": "evidenced"}, {"step": "Self-approve where the review is immaterial", "source": "evidenced"}, {"step": "Schedule the next review date on completion", "source": "inferred", "note": "Standard review-cycle behaviour (surfaced via continuous credit monitoring, 808); SME to confirm cadence config."}], "common_integrations": [], "community_articles": [{"title": "How to Use Credit Review", "url": "https://ncino.my.site.com/s/article/HowtoUseCreditReview"}]},
  807: {"description": "An automated variant of the periodic review where an AI agent — nCino's Banking Advisor — performs the review rather than a human. The main difference from a standard review is that the work is carried out agentically. Links to the heat map box 'Agentic Reviews'.", "roles": [], "process_steps": [{"step": "Instead of a human carrying out the review, an agent performs it", "source": "evidenced"}, {"step": "Use the Banking Advisor feature to run the agentic review", "source": "evidenced"}, {"step": "Assign Banking Advisor skills that gather review inputs (collateral, spreads, exposure, covenants) and draft the review", "source": "inferred", "note": "Banking Advisor is skill-based and consumes intelligence units (see 1001); SME to confirm which review skills are enabled for Raiffeisen."}, {"step": "Human reviews/approves the agent-produced output before completion", "source": "inferred", "note": "SME to confirm whether a human sign-off is required."}], "common_integrations": [], "community_articles": [{"title": "How to Use Continuous Credit Monitoring", "url": "https://ncino.my.site.com/s/article/HowtoUseContinuousCreditMonitoring"}, {"title": "How to Configure Continuous Credit Monitoring", "url": "https://ncino.my.site.com/s/article/HowtoConfigureContinuousCreditMonitoring"}]},
  808: {"description": "A dashboard feature that summarises all the monitoring activity in one place — financial information, next review date, covenant performance and other key details, plus live information about the customer. It rolls up the reviews, collateral and exposure into a single view, known as portfolio monitoring or continuous credit monitoring. It is not an active process step or stage but a feature. Links to the heat map box 'Portfolio Monitoring — Continuous Credit Monitoring'.", "roles": [], "process_steps": [{"step": "Aggregate financial information and monitoring data into a single dashboard", "source": "evidenced"}, {"step": "Surface the next review date, covenant performance and key details", "source": "evidenced"}, {"step": "Show live information about the bank's customer in one place", "source": "evidenced"}, {"step": "Roll up reviews, collateral and exposure into the single view", "source": "evidenced"}, {"step": "Drill from the dashboard into the underlying loan/covenant/review records", "source": "inferred", "note": "Standard dashboard navigation; SME to confirm."}], "common_integrations": [], "community_articles": [{"title": "How to Use Continuous Credit Monitoring - 2025_11", "url": "https://ncino.my.site.com/s/article/HowtoUseContinuousCreditMonitoring202511"}, {"title": "How to Configure Continuous Credit Monitoring - 2026_04", "url": "https://ncino.my.site.com/s/article/HowtoConfigureContinuousCreditMonitoring202604"}]},
  809: {"description": "Credit actions cover changes to a loan during its lifecycle: renewals (e.g. renewing a five-year line of credit for another five years — a separate process similar to the original credit approval), modifications (changing loan amounts, e.g. 20m to 25m — creates a copy of the loan and puts the relevant information through for approval), and extensions (extending the term). All are classified under credit actions and follow the same qualification → underwriting → approval process, but accelerated because the basic information is copied across. Links to the heat map box 'Renew/Modify/Extend Loan(s) — Credit Actions'.", "roles": [], "process_steps": [{"step": "Identify the lifecycle change required: renewal, modification or extension", "source": "evidenced"}, {"step": "Renewal: renew the line of credit for a further term as a separate process similar to the credit approval", "source": "evidenced"}, {"step": "Modification: change loan amounts — nCino creates a copy of the loan and puts the relevant information through for approval", "source": "evidenced"}, {"step": "Extension: extend the loan term", "source": "evidenced"}, {"step": "Run the credit action through the same qualification → underwriting → approval flow, accelerated via copied information", "source": "evidenced"}, {"step": "On approval, book the changed loan back to the core", "source": "inferred", "note": "Mirrors the original booking step (801); SME to confirm."}], "common_integrations": [], "community_articles": [{"title": "How to Use Loan Renewals and Loan Modifications", "url": "https://ncino.my.site.com/s/article/HowtoUseLoanRenewalsandLoanModifications"}, {"title": "How to Configure Loan Renewals and Loan Modifications", "url": "https://ncino.my.site.com/s/article/HowtoConfigureLoanRenewalsandLoanModifications"}, {"title": "How to Use Credit Actions on Product Package", "url": "https://ncino.my.site.com/s/article/HowtoUseCreditActionsonProductPackage"}, {"title": "How to Use Credit Actions on Relationship", "url": "https://ncino.my.site.com/s/article/HowtoUseCreditActionsonRelationship"}, {"title": "How to Configure Credit Actions - 2025_11", "url": "https://ncino.my.site.com/s/article/HowtoConfigureCreditActions202511"}, {"title": "How to Use Short Term Extensions", "url": "https://ncino.my.site.com/s/article/HowtoUseShortTermExtensions"}, {"title": "How to Use Credit Actions APIs", "url": "https://ncino.my.site.com/s/article/HowtoUseCreditActionsAPIs"}]},
  810: {"description": "An unhappy-path action where a loan at risk — the customer is missing repayments or may become delinquent — is handed over to the bank's Business Support Unit (BSU) to try to help the customer before they default. Handing the loan over to this different unit follows a very different process from the standard lifecycle. Links to the heat map box 'Handover Loans to BSU — Handover Loans'.", "roles": [], "process_steps": [{"step": "Identify a loan at risk (missed repayments / potential delinquency)", "source": "evidenced"}, {"step": "Hand the loan over to the BSU (a different unit within the bank) to attempt to help the customer beforehand", "source": "evidenced"}, {"step": "Follow the BSU's distinct handover process (different from the standard lifecycle)", "source": "evidenced"}, {"step": "Reassign ownership / loan team and apply problem-loan tracking on handover", "source": "inferred", "note": "Standard handover/problem-loan handling; SME to confirm the BSU process and statuses for Raiffeisen."}], "common_integrations": [], "community_articles": [{"title": "How to Use Handover Loans", "url": "https://ncino.my.site.com/s/article/HandoverLoansUserGuide"}, {"title": "How to Configure Handover Loans", "url": "https://ncino.my.site.com/s/article/HandoverLoansforImplementationConsultants"}]},
  811: {"description": "During the loan lifecycle most documents (fees, repayments) are generated by the core system and nCino does not need to know about them; however, where covenants are being breached the covenant-breach documents can be generated from nCino. This is where those breach documents are produced. Links to the heat map box 'Breach Document Generation — DocGen / FormsGen'.", "roles": [], "process_steps": [{"step": "Detect a covenant breach during the loan lifecycle (links to covenant servicing/testing, 802/803)", "source": "evidenced"}, {"step": "Generate the covenant-breach documents from nCino (rather than the core)", "source": "evidenced"}, {"step": "Use a standardised breach template with merge variables (customer, covenant, breach detail)", "source": "inferred", "note": "Standard DocGen template behaviour; SME to confirm breach templates for Raiffeisen."}, {"step": "Issue the breach document to the customer / store on the loan", "source": "inferred", "note": "SME to confirm distribution and storage."}], "common_integrations": [], "community_articles": [{"title": "How to Use nCinos Document Generation", "url": "https://ncino.my.site.com/s/article/HowtoUsenCinosDocumentGeneration"}, {"title": "How to Configure nCinos Document Generation", "url": "https://ncino.my.site.com/s/article/HowtoConfigurenCinosDocumentGeneration"}, {"title": "How to Use Form Generation", "url": "https://ncino.my.site.com/s/article/HowtoUseFormGeneration"}, {"title": "How to Configure Form Generation - Required Configuration", "url": "https://ncino.my.site.com/s/article/HowtoConfigureFormGeneration"}, {"title": "How to Configure HTML Form Generation", "url": "https://ncino.my.site.com/s/article/HowtoConfigureHTMLFormGeneration"}]},
  901: {"description": "One of the unhappy-path routes by which a loan moves to Complete. When a customer gets into enough trouble that the bank moves beyond the BSU handover into collections, this is the process of collecting on the loan to recover what has been secured against it. The transcript is explicit that there is no formalised, out-of-the-box auto-box process for collections in nCino — it is a 'various different process' configured per bank (go through X, Y, Z to collect on the loan). Linked to the heat map box 'Collections'; sits alongside Recoveries (902) as a separate path to Complete, downstream of Handover Loans to BSU (810).", "roles": [], "process_steps": [{"step": "Loan moves toward Complete via the collections route after the customer gets into trouble (beyond the BSU handover)", "source": "evidenced"}, {"step": "Work through the bank-specific collections process (go through X, Y, Z) to collect on the loan and recover what is secured against it", "source": "evidenced", "note": "Transcript: no formalised auto-box process in nCino; configured per bank"}, {"step": "Configure the collections steps/stages per the individual bank's policy (there is no standard nCino collections box)", "source": "inferred", "note": "Reflects transcript statement that collections is configured per bank; SME to confirm the specific configured flow for Raiffeisen"}], "common_integrations": [], "community_articles": []},
  902: {"description": "The second unhappy-path route by which a loan moves to Complete (shares the transcript slice with Collections, 901). When a customer gets into enough trouble, recoveries is the process of recovering the loan / collecting on it to get back what has been secured against it. As with collections, the transcript is explicit that there is no formalised, out-of-the-box auto-box process for recoveries in nCino — it is a 'various different process' configured per bank. Linked to the heat map box 'Recoveries'; sits alongside Collections (901) as a separate path to Complete, downstream of Handover Loans to BSU (810).", "roles": [], "process_steps": [{"step": "Loan moves toward Complete via the recoveries route after the customer gets into serious trouble", "source": "evidenced"}, {"step": "Work through the bank-specific recoveries process to recover the loan / collect what is secured against it", "source": "evidenced", "note": "Transcript: no formalised auto-box process in nCino; configured per bank"}, {"step": "Configure the recoveries steps/stages per the individual bank's policy (there is no standard nCino recoveries box)", "source": "inferred", "note": "Reflects transcript statement that recoveries is configured per bank; SME to confirm the specific configured flow for Raiffeisen"}], "common_integrations": [], "community_articles": []},
  903: {"description": "Regardless of how the loan closes or completes in nCino, any collateral that was securing the loan is then released. Where a lien had been registered on a government third-party register, the release makes the collateral available for other banks to use, or returns full ownership to the customer with no liens remaining against it. This is the point at which collateral is released. On the happy path, once a loan is paid off (e.g. a 20-year loan paid in full) it moves to Complete — usually by instruction from the core system via integration, or manually changed by an authorised user (kept very restrictive, typically 2 or 3 admins). Links to the heat map box 'Collateral release' (Collateral Management).", "roles": ["Authorised user / admin (move-to-complete kept restrictive, ~2-3 admins)"], "process_steps": [{"step": "Loan reaches Complete (happy path: paid off in full; or via any close/complete route)", "source": "evidenced"}, {"step": "Release the collateral that was securing the loan", "source": "evidenced"}, {"step": "Update the third-party government register where the lien was registered so the collateral is freed (available to other banks / full ownership returns to customer, no liens remaining)", "source": "evidenced"}, {"step": "Move the loan to Complete — usually by instruction from the core system via integration, or manually by an authorised user (restricted to ~2-3 admins)", "source": "evidenced"}, {"step": "Update the lien / collateral records in nCino to reflect the released status", "source": "inferred", "note": "Standard nCino collateral management behaviour; SME to confirm release field/status config for Raiffeisen"}], "common_integrations": ["Government third-party collateral/lien register", "Core system"], "community_articles": [{"title": "How to Configure Collateral Management - PART ONE - 2025_09", "url": "https://ncino.my.site.com/s/article/HowtoConfigureCollateralManagementPARTONE202509"}, {"title": "Gold Standard: Collateral Management", "url": "https://ncino.my.site.com/s/article/kAHHu000000XZTyOAO"}]},
  1001: {"description": "nCino's AI agent, positioned in the heat map as the 'intelligence unit'. Banking Advisor is the agentic AI aspect of the platform: a set of skills can be assigned to it to take actions on the user's behalf, summarise records, or run certain workflows. It consumes what nCino calls 'intelligence units' and can work across any aspect of the loan lifecycle, making it cross-cutting rather than tied to a single stage. The transcript explicitly frames this as a feature, not a process. Links to the heat map box 'Banking Advisor (Intelligence Units)'.", "roles": ["N/A — cross-cutting feature; no specific role named in transcript"], "process_steps": [{"step": "Not a process — Banking Advisor is a cross-cutting feature (agentic AI), not a process step", "source": "evidenced", "note": "Transcript: 'It's not a process, but more of a feature.'"}, {"step": "Functionality: assign skills to Banking Advisor to perform actions on the user's behalf, summarise records, or run workflows", "source": "evidenced"}, {"step": "Functionality: Banking Advisor consumes 'intelligence units' as it operates and can work across any aspect of the loan lifecycle", "source": "evidenced"}], "common_integrations": [], "community_articles": [{"title": "How to Use Banking Advisor Agents - 2025_07", "url": "https://ncino.my.site.com/s/article/HowtoUseBankingAdvisorAgents202507"}, {"title": "How to Configure Banking Advisor Agents - 2025_05", "url": "https://ncino.my.site.com/s/article/HowtoConfigureBankingAdvisorAgents202505"}]},
  1002: {"description": "Native reporting and dashboarding functionality that can be used across the entirety of the process and throughout nCino. Because all information is held in nCino, users can build reports against any data point, and where reports have visuals associated with them those can be assembled into dashboards. Reports and dashboards span any data point across the full loan lifecycle, making this a cross-cutting feature. Links to the heat map box 'Reports & Dashboards'.", "roles": ["N/A — cross-cutting feature; no specific role named in transcript"], "process_steps": [{"step": "Not a process — Reports & Dashboards is cross-cutting reporting functionality usable across the entire process, not a process step", "source": "evidenced"}, {"step": "Functionality: build reports against any data point held in nCino", "source": "evidenced"}, {"step": "Functionality: build dashboards from reports that have visuals associated with them", "source": "evidenced"}], "common_integrations": [], "community_articles": [{"title": "How to Customize Reports", "url": "https://ncino.my.site.com/s/article/kAHHu000000XaAFOA0"}]},
  1003: {"description": "A digital checklist feature used for operational risks or any set of activities that need to be completed, previously referenced in the context of closing checks. A Smart Checklist can exist at product package, relationship, loan, or even collateral level. It works well alongside conditions and requirements in nCino, with the related features driving the checklist items. Cross-cutting rather than tied to a single stage. Links to the heat map box 'Smart Checklist'.", "roles": ["N/A — cross-cutting feature; no specific role named in transcript (operational users implied via Priority Manager linkage)"], "process_steps": [{"step": "Not a process — Smart Checklist is a cross-cutting feature (a digital checklist), not a process step", "source": "evidenced"}, {"step": "Functionality: create a digital checklist at product package, relationship, loan, or collateral level", "source": "evidenced"}, {"step": "Functionality: use the checklist for operational risks or any activities that need completing", "source": "evidenced"}, {"step": "Functionality: relate the checklist to conditions and requirements so those features drive the items", "source": "evidenced"}, {"step": "Configure Smart Checklist templates and tie items to conditions/requirements per object type", "source": "inferred", "note": "Standard nCino Smart Checklist config; SME to confirm Raiffeisen setup"}], "common_integrations": [], "community_articles": [{"title": "How to Use Smart Checklist", "url": "https://ncino.my.site.com/s/article/HowtoUseSmartChecklist"}, {"title": "How to Configure Smart Checklist", "url": "https://ncino.my.site.com/s/article/HowtoConfigureSmartChecklist"}]},
  1004: {"description": "A consolidated view for operations users, surfaced in its own tab, that summarises the loans potentially requiring action. Rather than an operational user hunting across multiple loans and customers, Priority Manager gives a single view of outstanding actions — covenants coming up due, Smart Checklist items due, and conditions that need to be evidenced. It works closely with Smart Checklist, covenants and conditions, and is most relevant post-approval, pre-booking, or during the monitoring phase. Cross-cutting feature. Links to the heat map box 'Priority Manager'.", "roles": ["Operations / operational user (primary — the audience for the Priority Manager view)"], "process_steps": [{"step": "Not a process — Priority Manager is a cross-cutting view/feature for operations users, not a process step", "source": "evidenced"}, {"step": "Functionality: present a single-tab view of outstanding actions across all loans (covenants coming due, Smart Checklist items due, conditions to be evidenced)", "source": "evidenced"}, {"step": "Functionality: works with Smart Checklist, covenants and conditions to aggregate items requiring action", "source": "evidenced"}, {"step": "Functionality: primarily used post-approval, pre-booking, or in the monitoring phase", "source": "evidenced"}], "common_integrations": [], "community_articles": [{"title": "How to Use Priority Manager", "url": "https://ncino.my.site.com/s/article/HowtoUsePriorityManager"}, {"title": "How to Configure Priority Manager", "url": "https://ncino.my.site.com/s/article/HowtoConfigurePriorityManager"}]},
  1005: {"description": "An nCino dashboard view focused on user adoption and operational metrics. It reports how many loans are proceeding through, the usage of certain features, and the high-level data points an organisation may need. The transcript describes it as just a dashboard view — a feature, not a process step. Cross-cutting. Links to the heat map box 'Operations Analytics'.", "roles": ["N/A — cross-cutting feature; no specific role named in transcript"], "process_steps": [{"step": "Not a process — Operations Analytics is a cross-cutting dashboard view/feature, not a process step", "source": "evidenced", "note": "Transcript: 'It's a feature, not a process step.'"}, {"step": "Functionality: dashboard view of user adoption — how many loans are proceeding through and usage of certain features", "source": "evidenced"}, {"step": "Functionality: surface high-level operational data points the organisation may need", "source": "evidenced"}], "common_integrations": [], "community_articles": [{"title": "How to Use Operations Analytics Dashboard", "url": "https://ncino.my.site.com/s/article/HowtoUseOperationsAnalyticsDashboard"}, {"title": "How to Configure Salesforce Orgs for Operations Analytics", "url": "https://ncino.my.site.com/s/article/HowtoConfigureSalesforceOrgsforOperationsAnalytics202507"}]},
  1006: {"description": "A summary feature that is simply a different way to phrase and display the origination stages — prospecting, qualification, underwriting, approval, processing, doc prep, final review, and booking and monitoring. The transcript is explicit that it is not a process but a presentation/summary feature, a different way to display the lifecycle across the UI. Cross-cutting. Links to the heat map box 'Loan Origination Path Bar'.", "roles": ["N/A — cross-cutting feature; no specific role named in transcript"], "process_steps": [{"step": "Not a process — the Loan Origination Path Bar is a summary/display feature, not a process step", "source": "evidenced", "note": "Transcript: 'It's not a process, but a summary feature, a different way we can display that.'"}, {"step": "Functionality: re-phrase and display the origination stages (prospecting, qualification, underwriting, approval, processing, doc prep, final review, booking and monitoring) as a path bar", "source": "evidenced"}], "common_integrations": [], "community_articles": [{"title": "How to Use Origination Path", "url": "https://ncino.my.site.com/s/article/HowtoUseOriginationPath"}, {"title": "How to Configure Origination Path", "url": "https://ncino.my.site.com/s/article/HowtoConfigureOriginationPath"}]},
};
